Please add all of the missing features back into the latest version:  import React, { useState, useRef, useEffect, useCallback, createContext, useContext, useMemo } from 'react';
import { initializeApp } from "firebase/app";
import { getAuth, signInAnonymously, onAuthStateChanged, signInWithCustomToken, setPersistence, browserLocalPersistence } from "firebase/auth";
import { getFirestore, collection, addDoc, query, onSnapshot, deleteDoc, doc, updateDoc, getDocs, writeBatch, setLogLevel } from "firebase/firestore";
import { Plus, Scissors, Play, Pause, Download, Sparkles, Copy, X, Lightbulb, Bot, FileVideo, Music, PlayCircle, Edit, Tv, MessageSquare, Settings, Upload, Trash2, Users, RefreshCw, Speaker, VolumeX, GalleryHorizontal, ArrowLeft, Zap, Eraser, History as ReplayIcon } from 'lucide-react';

// --- Helper Functions ---
const cn = (...classes) => classes.filter(Boolean).join(' ');
const DEFAULT_MODEL = 'gemini-2.0-flash';

const PRESET_CHARACTERS = [
    { name: "Default Assistant", prompt: "You are a helpful assistant." },
    { name: "Sarcastic Teenager", prompt: "You are a sarcastic teenager who is always bored and unimpressed. Use slang like 'bet', 'no cap', and 'rizz'." },
    { name: "Over-enthusiastic Golden Retriever", prompt: "You are a golden retriever. You are incredibly friendly, enthusiastic, and easily distracted by squirrels." },
    { name: "Film Noir Detective", prompt: "You're a hardboiled detective in a rainy city. Speak in metaphors and be world-weary." },
    { name: "Shakespearean Actor", prompt: "Forsooth! Thou art a Shakespearean thespian. Speak in iambic pentameter and use thee/thou." },
];

const resizeImage = (base64Str, maxWidth = 128, maxHeight = 128) => {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
            try {
                const canvas = document.createElement('canvas');
                let { width, height } = img;

                if (width > height) {
                    if (width > maxWidth) {
                        height = Math.round(height * (maxWidth / width));
                        width = maxWidth;
                    }
                } else {
                    if (height > maxHeight) {
                        width = Math.round(width * (maxHeight / height));
                        height = maxHeight;
                    }
                }

                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', 0.9));
            } catch (error) {
                reject(error);
            }
        };
        img.onerror = () => reject(new Error("Failed to load image"));
        img.src = base64Str;
    });
};

const playSound = (sound) => {
    // Sound generation using Tone.js for UI feedback
    if (typeof window.Tone !== 'undefined') {
        try {
            const synth = new window.Tone.Synth().toDestination();
            const pluckSynth = new window.Tone.PluckSynth().toDestination();
            const noiseSynth = new window.Tone.NoiseSynth().toDestination();

            switch (sound) {
                case 'beep': synth.triggerAttackRelease("C4", "8n"); break;
                case 'swoosh': noiseSynth.triggerAttackRelease("4n"); break;
                case 'sparkle': pluckSynth.triggerAttackRelease("C5", "8n"); break;
                case 'click': pluckSynth.triggerAttackRelease("C2", "16n"); break;
                case 'gentle hum': synth.triggerAttackRelease("C2", "2n"); break;
                case 'rising synth':
                    synth.triggerAttackRelease("C4", "4n");
                    setTimeout(() => synth.triggerAttackRelease("E4", "4n"), 150);
                    setTimeout(() => synth.triggerAttackRelease("G4", "4n"), 300);
                    break;
                default: synth.triggerAttackRelease("A3", "8n"); break;
            }
        } catch (error) {
            console.warn('Tone.js error:', error);
        }
    }
};

// --- UI Components ---

const Splash = () => (
    // Splash screen for loading state
    <div className="fixed inset-0 bg-gray-900 flex items-center justify-center text-white">
        <div className="text-center">
            <div className="animate-pulse flex flex-col items-center space-y-4">
                 <Bot size={48} className="text-blue-500"/>
                 <p className="text-lg text-gray-400">Loading Creative Suite...</p>
            </div>
        </div>
    </div>
);

const Modal = ({ isOpen, onClose, title, children, icon, maxWidth = 'max-w-md' }) => {
    // Reusable modal component
    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/75 z-50 flex items-center justify-center p-4" onClick={onClose}>
            <div 
                className={`bg-gray-800 rounded-lg shadow-xl w-full ${maxWidth} max-h-[90vh] flex flex-col`}
                onClick={e => e.stopPropagation()}
            >
                <div className="p-4 border-b border-gray-700 flex justify-between items-center sticky top-0 bg-gray-800 z-10 flex-shrink-0">
                    <h3 className="text-lg font-bold flex items-center">
                        {icon && React.cloneElement(icon, { className: "mr-2" })}
                        {title}
                    </h3>
                    <button onClick={onClose} className="text-gray-400 hover:text-white">
                        <X size={20} />
                    </button>
                </div>
                <div className="p-4 overflow-y-auto">
                    {children}
                </div>
            </div>
        </div>
    );
};

const AgentForm = ({ onSave, onUpdate, onRemove, voices, agentToEdit, onBack, setIsConfirmModalOpen, setConfirmAction, setConfirmMessage }) => {
    // Form for creating/editing a single agent
    const [name, setName] = useState(agentToEdit?.name || '');
    const [systemPrompt, setSystemPrompt] = useState(agentToEdit?.systemPrompt || '');
    const [voice, setVoice] = useState(agentToEdit?.voice || voices[0]?.name || '');
    const [isPresetOpen, setIsPresetOpen] = useState(false);

    useEffect(() => {
        if (agentToEdit) {
            setName(agentToEdit.name);
            setSystemPrompt(agentToEdit.systemPrompt);
            setVoice(agentToEdit.voice || voices[0]?.name || '');
        } else {
            setName('');
            setSystemPrompt('');
            setVoice(voices[0]?.name || '');
        }
    }, [agentToEdit, voices]);

    const handleSubmit = (e) => {
        e.preventDefault();
        const agentData = { name, systemPrompt, voice, model: DEFAULT_MODEL };
        if (agentToEdit) {
            onUpdate({ ...agentData, id: agentToEdit.id });
        } else {
            onSave(agentData);
        }
        onBack();
    };

    const handlePresetSelect = (preset) => {
        setName(preset.name);
        setSystemPrompt(preset.prompt);
        setIsPresetOpen(false);
    };

    return (
        <div className="flex flex-col h-full">
            <form onSubmit={handleSubmit} className="space-y-4 flex-grow">
                <div>
                    <label className="block text-sm font-medium mb-1">Name</label>
                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded" required />
                </div>
                <div>
                    <label className="block text-sm font-medium mb-1">System Prompt</label>
                    <textarea value={systemPrompt} onChange={(e) => setSystemPrompt(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]" required />
                </div>
                {voices.length > 0 && (
                    <div>
                        <label className="block text-sm font-medium mb-1">Voice</label>
                        <select value={voice} onChange={(e) => setVoice(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded">
                            {voices.map(v => <option key={v.name} value={v.name}>{v.name} ({v.lang})</option>)}
                        </select>
                    </div>
                )}
            </form>

            <div className="flex justify-between items-center pt-4 mt-4 border-t border-gray-700 flex-shrink-0">
                <button type="button" onClick={onBack} className="px-3 py-1 bg-gray-600 rounded text-sm flex items-center"><ArrowLeft size={16} className="mr-1" /> Back</button>
                <div className="space-x-2">
                    <button type="button" onClick={() => setIsPresetOpen(true)} className="px-3 py-1 bg-gray-600 rounded text-sm">Presets</button>
                    {agentToEdit && <button type="button" onClick={() => {
                        setConfirmMessage(`Delete ${agentToEdit.name}? This cannot be undone.`);
                        setConfirmAction(() => () => { onRemove(agentToEdit.id); onBack(); });
                        setIsConfirmModalOpen(true);
                    }} className="px-3 py-1 bg-red-500 rounded text-sm">Delete</button>}
                    <button type="button" onClick={handleSubmit} className="px-4 py-2 bg-blue-500 rounded text-white">{agentToEdit ? "Update" : "Create"}</button>
                </div>
            </div>

            <Modal isOpen={isPresetOpen} onClose={() => setIsPresetOpen(false)} title="Character Presets" maxWidth="max-w-sm">
                <div className="space-y-2">
                    {PRESET_CHARACTERS.map((preset, i) => (
                        <button key={i} onClick={() => handlePresetSelect(preset)} className="w-full p-3 bg-gray-700 hover:bg-gray-600 rounded text-left">
                            <div className="font-medium">{preset.name}</div>
                            <div className="text-xs text-gray-400 truncate">{preset.prompt}</div>
                        </button>
                    ))}
                </div>
            </Modal>
        </div>
    );
};

const AgentManagerModal = ({ isOpen, onClose, agents, ...rest }) => {
    // Modal for managing agents: viewing list and initiating create/edit
    const [view, setView] = useState('list'); // 'list' or 'form'
    const [currentAgent, setCurrentAgent] = useState(null);

    const handleEdit = (agent) => {
        setCurrentAgent(agent);
        setView('form');
    };

    const handleAdd = () => {
        setCurrentAgent(null);
        setView('form');
    };

    const handleBack = () => {
        setView('list');
        setCurrentAgent(null);
    };

    useEffect(() => {
        if (isOpen) {
            setView('list'); // Reset to list view when modal is opened
        }
    }, [isOpen]);

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={view === 'list' ? 'Manage Agents' : (currentAgent ? 'Edit Agent' : 'Create Agent')} icon={<Users />} maxWidth="max-w-2xl">
            {view === 'list' ? (
                <div className="space-y-3">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                        {agents.map(agent => (
                            <div key={agent.id} className="bg-gray-700 p-3 rounded-lg flex items-start space-x-3">
                                <img
                                    src={agent.profilePictureUrl || `https://placehold.co/64x64/7c3aed/ffffff?text=${agent.name.charAt(0)}`}
                                    alt={agent.name}
                                    className="w-16 h-16 rounded-md object-cover flex-shrink-0"
                                />
                                <div className="flex-grow">
                                    <h4 className="font-bold">{agent.name}</h4>
                                    <p className="text-xs text-gray-400 italic line-clamp-2">{agent.systemPrompt}</p>
                                    <button onClick={() => handleEdit(agent)} className="mt-2 text-xs px-2 py-1 bg-blue-600 rounded">Edit</button>
                                </div>
                            </div>
                        ))}
                    </div>
                    {agents.length === 0 && <p className="text-gray-500 text-center py-8">No agents created yet.</p>}
                    <div className="pt-4 text-center">
                        <button onClick={handleAdd} className="px-4 py-2 bg-green-600 rounded-lg">
                            <Plus className="inline mr-2" size={16}/>Add New Agent
                        </button>
                    </div>
                </div>
            ) : (
                <AgentForm agentToEdit={currentAgent} onBack={handleBack} {...rest} />
            )}
        </Modal>
    );
};


const GoalModal = ({ isOpen, onClose, onSet, initialGoal }) => {
    // Modal for setting the conversation goal
    const [goal, setGoal] = useState(initialGoal || '');

    useEffect(() => {
        setGoal(initialGoal || '');
    }, [initialGoal]);

    const handleSubmit = (e) => {
        e.preventDefault();
        onSet(goal);
        onClose();
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Set Conversation Goal" icon={<Lightbulb />}>
            <form onSubmit={handleSubmit} className="space-y-4">
                <textarea
                    value={goal}
                    onChange={(e) => setGoal(e.target.value)}
                    className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]"
                    placeholder="Example: 'Plan a heist to steal the Mona Lisa'"
                />
                <div className="flex justify-end">
                    <button
                        type="submit"
                        className="px-4 py-2 bg-blue-500 rounded text-white"
                    >
                        Set Goal
                    </button>
                </div>
            </form>
        </Modal>
    );
};

const RuleModal = ({ isOpen, onClose, rules, agents }) => {
    // Displays the active, AI-generated conversation rules
    const getAgentName = (id) => agents.find(a => a.id === id)?.name || 'Unknown';

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Active Conversation Rules" icon={<Copy />}>
            <div className="space-y-4">
                <p className="text-gray-400">
                    These are the active rules driving the conversation in 'auto' mode, generated by AI based on the scenario goal and agent personas.
                </p>
                {rules.length > 0 ? (
                    <div className="bg-gray-900 p-3 rounded space-y-2">
                        {rules.map((rule, i) => (
                             <div key={i} className="flex items-center space-x-2 text-sm">
                                <span>{getAgentName(rule.sourceId)}</span>
                                <span className="text-blue-400">→</span>
                                <span>{getAgentName(rule.targetId)}</span>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className="text-center text-gray-500 py-4">No rules generated yet. Use the 'Automate' feature to create a scenario.</p>
                )}
            </div>
        </Modal>
    );
};

const TopicModal = ({ isOpen, onClose, onInject, onSuggest }) => {
    // Modal for injecting a new topic into the conversation
    const [topic, setTopic] = useState('');
    const [isSuggesting, setIsSuggesting] = useState(false);

    const handleSubmit = (e) => {
        e.preventDefault();
        if(topic.trim()){
            onInject(topic);
            setTopic('');
            onClose();
        }
    };

    const handleSuggest = async () => {
        setIsSuggesting(true);
        const suggestion = await onSuggest();
        setTopic(suggestion);
        setIsSuggesting(false);
    }

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Inject New Topic" icon={<Zap />}>
             <form onSubmit={handleSubmit} className="space-y-4">
                <textarea
                    value={topic}
                    onChange={(e) => setTopic(e.target.value)}
                    className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]"
                    placeholder="Example: 'Suddenly, the power goes out...' or 'A mysterious stranger enters the room.'"
                />
                <div className="flex justify-between">
                    <button type="button" onClick={handleSuggest} className="px-4 py-2 bg-purple-600 text-white rounded-lg flex items-center" disabled={isSuggesting}>
                        <Sparkles size={16} className="mr-2"/> {isSuggesting ? "Suggesting..." : "Suggest Topic"}
                    </button>
                    <button type="submit" className="px-4 py-2 bg-blue-500 rounded text-white">Inject Topic</button>
                </div>
            </form>
        </Modal>
    );
}

const ClearModal = ({ isOpen, onClose, onClearMessages, onClearAll }) => {
    // Modal for clearing conversation or full reset
    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Clear Scenario" icon={<Eraser />}>
             <div className="space-y-4 text-center">
                <p className="text-gray-300">Choose what you would like to clear.</p>
                <div className="flex justify-center space-x-4 pt-2">
                    <button onClick={() => {onClearMessages(); onClose();}} className="px-4 py-2 bg-yellow-600 text-white rounded-lg">Clear Messages Only</button>
                    <button onClick={() => {onClearAll(); onClose();}} className="px-4 py-2 bg-red-500 text-white rounded-lg">Clear Entire Scenario</button>
                </div>
            </div>
        </Modal>
    );
}

const MediaBin = ({ title, clips, onAddToTimeline, onFileUpload, onMetadata, type, setImagePreviewUrl }) => {
    // UI for media clips (video/audio)
    const fileInputRef = useRef(null);

    const handleFileClick = () => {
        fileInputRef.current.click();
    };

    return (
        <div className="bg-gray-800 rounded-lg p-3">
            <div className="flex justify-between items-center mb-3">
                <h3 className="font-semibold">{title}</h3>
                <button 
                    onClick={handleFileClick}
                    className="p-1 bg-gray-700 rounded hover:bg-gray-600"
                    title="Upload media"
                >
                    <Upload size={16} />
                </button>
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={(e) => onFileUpload(e, type)}
                    accept={type === 'video' ? 'video/*' : 'audio/*'}
                    multiple
                    className="hidden"
                />
            </div>
            <div className="space-y-2 max-h-64 overflow-y-auto">
                {clips.length === 0 ? (
                    <p className="text-center text-gray-500 py-4 text-sm">No {type} clips</p>
                ) : (
                    clips.map(clip => (
                        <div key={clip.id} className="flex items-center justify-between bg-gray-700 p-2 rounded">
                           <div className="flex items-center space-x-2 truncate cursor-pointer" onClick={() => clip.type === 'image' && setImagePreviewUrl(clip.url)}>
                                {clip.type === 'video' ? <FileVideo size={16} /> : clip.type === 'image' ? <img src={clip.url} className="w-8 h-8 object-cover rounded"/> : <Music size={16} />}
                                <span className="truncate text-sm">{clip.name}</span>
                            </div>
                            <button 
                                onClick={() => onAddToTimeline(clip, type)}
                                className="p-1 bg-blue-500 rounded hover:bg-blue-400"
                                title="Add to timeline"
                            >
                                <Plus size={16} />
                            </button>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

const Timeline = ({ videoTracks, audioTracks, onRemove, currentTime, totalDuration, containerRef }) => {
    // Video editor timeline display
    const calculatePosition = (startTime, duration) => {
        if (!totalDuration) return 0;
        return `${(startTime / totalDuration) * 100}%`;
    };

    const calculateWidth = (duration, totalDuration) => {
        if (!totalDuration) return '0%';
        return `${(duration / totalDuration) * 100}%`;
    };

    return (
        <div className="bg-gray-800 rounded-lg p-3 flex-1 overflow-x-auto" ref={containerRef}>
            <div className="relative h-20 mb-2 min-w-full" style={{ width: `${Math.max(100, totalDuration * 10)}%` }}>
                {/* Video Track */}
                <div className="absolute top-0 left-0 right-0 h-10 bg-gray-700 rounded">
                    {videoTracks.map((clip, index) => {
                        let startTime = 0;
                        for (let i = 0; i < index; i++) {
                            startTime += videoTracks[i].duration || 0;
                        }
                        return (
                            <div
                                key={clip.id}
                                className="absolute h-full bg-blue-500 rounded border border-blue-400 flex items-center justify-center"
                                style={{
                                    left: calculatePosition(startTime, totalDuration),
                                    width: calculateWidth(clip.duration || 0, totalDuration),
                                }}
                            >
                                <span className="text-xs truncate px-1">{clip.name}</span>
                                <button
                                    onClick={() => onRemove(clip.id, 'video')}
                                    className="absolute -right-2 -top-2 bg-red-500 rounded-full p-1 hover:bg-red-400"
                                >
                                    <X size={12} />
                                </button>
                            </div>
                        );
                    })}
                </div>

                {/* Audio Track */}
                <div className="absolute top-12 left-0 right-0 h-10 bg-gray-700 rounded">
                    {audioTracks.map((clip, index) => {
                        let startTime = 0;
                        for (let i = 0; i < index; i++) {
                            startTime += audioTracks[i].duration || 0;
                        }
                        return (
                            <div
                                key={clip.id}
                                className="absolute h-full bg-green-500 rounded border border-green-400 flex items-center justify-center"
                                style={{
                                    left: calculatePosition(startTime, totalDuration),
                                    width: calculateWidth(clip.duration || 0, totalDuration),
                                }}
                            >
                                <span className="text-xs truncate px-1">{clip.name}</span>
                                <button
                                    onClick={() => onRemove(clip.id, 'audio')}
                                    className="absolute -right-2 -top-2 bg-red-500 rounded-full p-1 hover:bg-red-400"
                                >
                                    <X size={12} />
                                </button>
                            </div>
                        );
                    })}
                </div>

                {/* Playhead */}
                <div
                    className="absolute top-0 w-0.5 h-full bg-red-500 z-10"
                    style={{ left: `${(currentTime / totalDuration) * 100}%` }}
                ></div>
            </div>
        </div>
    );
};

const Toolbar = ({ onPlayPause, isPlaying, currentTime, totalDuration, onAiStoryboard, onAiClipIdeas, onSuggestTitle, onGenerateDescription }) => {
    // Toolbar with playback and AI controls
    const formatTime = (seconds) => {
        const mins = Math.floor(seconds / 60);
        const secs = Math.floor(seconds % 60);
        return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
    };

    return (
        <div className="bg-gray-800 rounded-lg p-3 mb-4 flex items-center justify-between">
            <div className="flex items-center space-x-4">
                <button
                    onClick={onPlayPause}
                    className="p-2 bg-blue-500 rounded-full hover:bg-blue-400"
                >
                    {isPlaying ? <Pause size={20} /> : <Play size={20} />}
                </button>
                <div className="text-sm font-mono">
                    {formatTime(currentTime)} / {formatTime(totalDuration)}
                </div>
            </div>

            <div className="flex items-center space-x-2">
                <button
                    onClick={onAiClipIdeas}
                    className="px-3 py-1 bg-purple-500 rounded text-sm flex items-center"
                >
                    <Sparkles size={16} className="mr-1" /> AI Clips
                </button>
                <button
                    onClick={onAiStoryboard}
                    className="px-3 py-1 bg-purple-500 rounded text-sm flex items-center"
                >
                    <GalleryHorizontal size={16} className="mr-1" /> Storyboard
                </button>
                <button
                    onClick={onSuggestTitle}
                    className="px-3 py-1 bg-yellow-500 rounded text-sm"
                >
                    Suggest Title
                </button>
                <button
                    onClick={onGenerateDescription}
                    className="px-3 py-1 bg-green-500 rounded text-sm"
                >
                    Generate Description
                </button>
            </div>
        </div>
    );
};

const DescriptionModal = ({ isOpen, onClose, isLoading, description, error, onRegenerate }) => {
    // Modal for AI-generated video descriptions
    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Video Description" icon={<Edit />}>
            <div className="space-y-4">
                {isLoading ? (
                    <div className="flex justify-center py-4">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500"></div>
                    </div>
                ) : error ? (
                    <div className="bg-red-900/50 p-3 rounded text-red-300">{error}</div>
                ) : (
                    <textarea
                        value={description}
                        readOnly
                        className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[200px] font-mono text-sm"
                    />
                )}

                <div className="flex justify-end space-x-2">
                    <button
                        onClick={onRegenerate}
                        disabled={isLoading}
                        className="px-3 py-1 bg-blue-500 rounded text-sm disabled:bg-gray-600"
                    >
                        Regenerate
                    </button>
                    <button
                        onClick={() => {
                            if (description) {
                                navigator.clipboard.writeText(description);
                            }
                        }}
                        className="px-3 py-1 bg-gray-600 rounded text-sm"
                    >
                        Copy
                    </button>
                </div>
            </div>
        </Modal>
    );
};

