                    <span>Agents ({agents.length})</span>
                </button>

                <button 
                    onClick={() => setIsGoalModalOpen(true)}
                    className="px-3 py-2 bg-orange-500 text-white rounded-lg text-sm hover:bg-orange-600"
                >
                    🎯 Set Goal
                </button>

                <button 
                    onClick={() => setIsRuleModalOpen(true)}
                    className="px-3 py-2 bg-yellow-500 text-black rounded-lg text-sm hover:bg-yellow-600"
                >
                    📜 Rules
                </button>

                <button 
                    onClick={handleAutomateAll}
                    disabled={isAutomating}
                    className="px-3 py-2 bg-purple-600 text-white rounded-lg text-sm hover:bg-purple-700 disabled:bg-purple-400"
                >
                    🚀 Automate
                </button>

                <button 
                    onClick={handleCreativeSynthesis}
                    disabled={isSynthesizing}
                    className="px-3 py-2 bg-cyan-600 text-white rounded-lg text-sm hover:bg-cyan-700 disabled:bg-cyan-400"
                >
                    {isSynthesizing ? synthesisStatus : '🎬 Creative Synthesis'}
                </button>

                <button onClick={() => setIsTopicModalOpen(true)} className="px-3 py-2 bg-indigo-500 text-white rounded-lg text-sm hover:bg-indigo-600"><Zap size={16} className="inline mr-1"/>Inject Topic</button>
                <button onClick={handleReplay} disabled={isReplaying} className="px-3 py-2 bg-teal-500 text-white rounded-lg text-sm hover:bg-teal-600 disabled:bg-teal-400"><ReplayIcon size={16} className="inline mr-1"/>Replay</button>
                <button onClick={() => setIsClearModalOpen(true)} className="px-3 py-2 bg-red-800 text-white rounded-lg text-sm hover:bg-red-700"><Eraser size={16} className="inline mr-1"/>Clear</button>


                <div className="flex-grow"></div>

                <div className="flex items-center gap-2">
                    <span className="text-sm font-medium">Mode:</span>
                    <button 
                        onClick={() => setMode(m => m === 'manual' ? 'auto' : 'manual')}
                        className={`px-3 py-1 rounded-full text-sm ${mode === 'auto' ? 'bg-blue-500 text-white' : 'bg-gray-600'}`}
                    >
                        {mode === 'auto' ? 'Auto' : 'Manual'}
                    </button>

                    {mode === 'auto' && (
                        <button 
                            onClick={() => setIsPaused(!isPaused)}
                            className="p-2 text-gray-400 hover:text-white rounded-full"
                        >
                            {isPaused ? <Play size={16} /> : <Pause size={16} />}
                        </button>
                    )}
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setIsTtsEnabled(!isTtsEnabled)}
                        className="p-2 text-gray-400 hover:text-white rounded-full"
                    >
                        {isTtsEnabled ? <Speaker size={16} /> : <VolumeX size={16} />}
                    </button>

                    <button 
                        onClick={() => setIsGalleryOpen(true)}
                        className="p-2 text-gray-400 hover:text-white rounded-full"
                    >
                        <GalleryHorizontal size={16} />
                    </button>
                </div>
            </header>

            {/* Messages area */}
            <main className="p-4 overflow-y-auto flex flex-col space-y-4">
                {displayMessages.length > 0 ? (
                    displayMessages.map(msg => (
                        <MessageBubble 
                            key={msg.id} 
                            msg={msg} 
                        />
                    ))
                ) : (
                    <div className="text-center text-gray-500 py-16">
                        No messages yet. Start by adding an agent or using the Automate feature.
                    </div>
                )}

                {isGenerating && <TypingIndicator />}
                <div ref={messagesEndRef} />
            </main>

            {/* Input area */}
            <footer className="bg-gray-800 shadow-inner p-4">
                <div className="flex items-center gap-2 mb-3">
                    <label className="text-sm">From:</label>
                    <select 
                        value={senderId}
                        onChange={e => setSenderId(e.target.value)}
                        className="w-full p-2 border rounded-lg bg-gray-700 border-gray-600 text-sm"
                    >
                        <option value="You">You</option>
                        {agents.map(a => (
                            <option key={a.id} value={a.id}>{a.name}</option>
                        ))}
                    </select>

                    <label className="text-sm">To:</label>
                    <select 
                        value={recipientAgentId}
                        onChange={e => setRecipientAgentId(e.target.value)}
                        className="w-full p-2 border rounded-lg bg-gray-700 border-gray-600"
                    >
                        <option value="">All</option>
                        {agents.map(a => (
                            <option key={a.id} value={a.id}>{a.name}</option>
                        ))}
                    </select>
                </div>

                <div className="flex items-center space-x-2">
                    <input
                        type="text"
                        ref={inputRef}
                        value={inputValue}
                        onChange={e => setInputValue(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder={isGenerating ? "Thinking..." : "Type a message..."}
                        disabled={isGenerating || agents.length === 0}
                        className="w-full p-2 bg-transparent border border-gray-600 rounded-full"
                    />

                    <button 
                        onClick={handleSendMessage}
                        className="p-3 bg-blue-500 text-white rounded-full disabled:bg-gray-400"
                        disabled={!inputValue.trim() || isGenerating || agents.length === 0}
                    >
                        <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 12h14M12 5l7 7-7 7" />
                        </svg>
                    </button>
                </div>
            </footer>

            {/* Modals */}
            <AgentManagerModal 
                isOpen={isAgentModalOpen}
                onClose={() => setIsAgentModalOpen(false)}
                onSave={handleAddAgent}
                onUpdate={handleUpdateAgent}
                onRemove={handleRemoveAgent}
                voices={voices}
                agents={agents}
                setIsConfirmModalOpen={setIsConfirmModalOpen}
                setConfirmAction={setConfirmAction}
                setConfirmMessage={setConfirmMessage}
            />

            <GoalModal 
                isOpen={isGoalModalOpen}
                onClose={() => setIsGoalModalOpen(false)}
                onSet={setConversationGoal}
                initialGoal={conversationGoal}
            />

            <RuleModal 
                isOpen={isRuleModalOpen}
                onClose={() => setIsRuleModalOpen(false)}
                rules={rules}
                agents={agents}
            />

            <SynthesisGalleryModal 
                isOpen={isGalleryOpen}
                onClose={() => setIsGalleryOpen(false)}
            />

            <TopicModal 
                isOpen={isTopicModalOpen}
                onClose={() => setIsTopicModalOpen(false)}
                onInject={handleInjectTopic}
                onSuggest={handleSuggestTopic}
            />

            <ClearModal
                isOpen={isClearModalOpen}
                onClose={() => setIsClearModalOpen(false)}
                onClearMessages={handleClearMessages}
                onClearAll={handleClearAll}
            />

            <ConfirmationModal 
                isOpen={isConfirmModalOpen}
                onClose={() => setIsConfirmModalOpen(false)}
                onConfirm={() => {
                    if (confirmAction) confirmAction();
                    setIsConfirmModalOpen(false);
                }}
                message={confirmMessage}
            />

            <ImagePreviewModal 
                imageUrl={imagePreviewUrl}
                onClose={() => setImagePreviewUrl(null)}
            />
        </div>
    );
};

