// --- App Context and Provider ---
const AppContext = createContext();

const AppProvider = ({ children }) => {
    // --- State Management ---

    // Shared State
    const [db, setDb] = useState(null);
    const [userId, setUserId] = useState(null);
    const [isAuthReady, setIsAuthReady] = useState(false);
    const [isDataLoading, setIsDataLoading] = useState(true);
    const [currentView, setCurrentView] = useState('chat');
    const appId = typeof __app_id !== 'undefined' ? __app_id : 'default-app-id';
    const collectionsRef = useRef({});

    // Video Editor State
    const [videoClips, setVideoClips] = useState([]);
    const [audioClips, setAudioClips] = useState([]);
    const [timelineVideo, setTimelineVideo] = useState([]);
    const [timelineAudio, setTimelineAudio] = useState([]);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentTime, setCurrentTime] = useState(0);
    const [previewSource, setPreviewSource] = useState(null);
    const [isDescriptionModalOpen, setIsDescriptionModalOpen] = useState(false);
    const [isGeneratingDescription, setIsGeneratingDescription] = useState(false);
    const [generatedDescription, setGeneratedDescription] = useState('');
    const [descriptionError, setDescriptionError] = useState('');
    const [isTitleModalOpen, setIsTitleModalOpen] = useState(false);
    const [isGeneratingTitle, setIsGeneratingTitle] = useState(false);
    const [generatedTitles, setGeneratedTitles] = useState([]);
    const [titleError, setTitleError] = useState('');
    const [isAiClipModalOpen, setIsAiClipModalOpen] = useState(false);
    const [isAiStoryboardModalOpen, setIsAiStoryboardModalOpen] = useState(false);

    // Chat State
    const [agents, setAgents] = useState([]);
    const [messages, setMessages] = useState([]);
    const [rules, setRules] = useState([]);
    const [synthesisJobs, setSynthesisJobs] = useState([]);
    const [isAgentModalOpen, setIsAgentModalOpen] = useState(false);
    const [voices, setVoices] = useState([]);
    const [inputValue, setInputValue] = useState('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [senderId, setSenderId] = useState('You');
    const [recipientAgentId, setRecipientAgentId] = useState('');
    const [conversationGoal, setConversationGoal] = useState("");
    const [isGoalModalOpen, setIsGoalModalOpen] = useState(false);
    const [isAutomating, setIsAutomating] = useState(false);
    const [isRuleModalOpen, setIsRuleModalOpen] = useState(false);
    const [isTtsEnabled, setIsTtsEnabled] = useState(false);
    const [responseDelay, setResponseDelay] = useState(1.5);
    const [isPaused, setIsPaused] = useState(true);
    const [mode, setMode] = useState('manual');
    const [isSynthesizing, setIsSynthesizing] = useState(false);
    const [synthesisStatus, setSynthesisStatus] = useState('');
    const [isGalleryOpen, setIsGalleryOpen] = useState(false);
    const [isTurnInProgress, setIsTurnInProgress] = useState(false);
    const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
    const [confirmAction, setConfirmAction] = useState(null);
    const [confirmMessage, setConfirmMessage] = useState('');
    const [imagePreviewUrl, setImagePreviewUrl] = useState(null);
    const [isTopicModalOpen, setIsTopicModalOpen] = useState(false);
    const [isClearModalOpen, setIsClearModalOpen] = useState(false);
    const [isReplaying, setIsReplaying] = useState(false);
    const [replayMessages, setReplayMessages] = useState([]);


    // Initialize Firebase and other services
    useEffect(() => {
        setLogLevel('debug');

        const firebaseConfig = typeof __firebase_config !== 'undefined' 
            ? JSON.parse(__firebase_config) 
            : null;

        if (!firebaseConfig) {
            console.warn("Firebase config not found.");
            setIsAuthReady(true);
            setIsDataLoading(false);
            return;
        }

        try {
            const app = initializeApp(firebaseConfig);
            const firestoreDb = getFirestore(app);
            const firebaseAuth = getAuth(app);

            setDb(firestoreDb);

            onAuthStateChanged(firebaseAuth, async (user) => {
                if (user) {
                    setUserId(user.uid);
                } else {
                    try {
                        const token = typeof __initial_auth_token !== 'undefined' 
                            ? __initial_auth_token 
                            : null;

                        if (token) {
                            await signInWithCustomToken(firebaseAuth, token);
                        } else {
                            await signInAnonymously(firebaseAuth);
                        }
                    } catch (error) {
                        console.error("Authentication failed:", error);
                    }
                }
                setIsAuthReady(true);
            });

            // Load Tone.js for audio feedback
            const script = document.createElement('script');
            script.src = "https://cdnjs.cloudflare.com/ajax/libs/tone/14.7.77/Tone.js";
            script.async = true;
            script.onload = () => {
                if (window.Tone) {
                    window.Tone.start();
                }
            };
            document.body.appendChild(script);

            // Load available system voices for TTS
            const loadVoices = () => {
                const availableVoices = window.speechSynthesis?.getVoices() || [];
                setVoices(availableVoices.map(v => ({ 
                    name: v.name, 
                    lang: v.lang,
                    voice: v
                })));
            };

            if (window.speechSynthesis) {
                window.speechSynthesis.onvoiceschanged = loadVoices;
                setTimeout(loadVoices, 100);
            }

            return () => {
                document.body.removeChild(script);
                if (window.speechSynthesis) {
                    window.speechSynthesis.onvoiceschanged = null;
                }
                if (window.Tone?.context) {
                    window.Tone.context.close();
                }
            };
        } catch (error) {
            console.error("Initialization error:", error);
            setIsAuthReady(true);
            setIsDataLoading(false);
        }
    }, []);

    // Set up Firestore listeners for real-time data synchronization
    useEffect(() => {
        if (!isAuthReady || !db || !userId) return;

        setIsDataLoading(true);
        const prefix = ['artifacts', appId, 'users', userId];

        const collectionDefs = {
            agents: { setter: setAgents },
            messages: { 
                setter: setMessages, 
                sort: (a, b) => a.timestamp?.toDate() - b.timestamp?.toDate() 
            },
            rules: { setter: setRules },
            synthesisJobs: { 
                setter: setSynthesisJobs, 
                sort: (a, b) => b.timestamp?.toDate() - a.timestamp?.toDate() 
            },
            videoClips: { 
                setter: setVideoClips, 
                sort: (a, b) => a.timestamp?.toDate() - b.timestamp?.toDate() 
            },
            audioClips: { 
                setter: setAudioClips, 
                sort: (a, b) => a.timestamp?.toDate() - b.timestamp?.toDate() 
            },
            timelineVideo: { 
                setter: setTimelineVideo, 
                sort: (a, b) => a.timestamp?.toDate() - b.timestamp?.toDate() 
            },
            timelineAudio: { 
                setter: setTimelineAudio, 
                sort: (a, b) => a.timestamp?.toDate() - b.timestamp?.toDate() 
            },
        };

        // Initialize collection references
        Object.keys(collectionDefs).forEach(key => {
            collectionsRef.current[key] = collection(db, ...prefix, key);
        });

        let loaded = 0;
        const totalCollections = Object.keys(collectionDefs).length;

        const markLoaded = () => {
            if (++loaded >= totalCollections) {
                setIsDataLoading(false);
            }
        };

        // Set up snapshot listeners
        const unsubs = Object.entries(collectionDefs).map(([key, { setter, sort }]) => {
            return onSnapshot(
                query(collectionsRef.current[key]), 
                (snap) => {
                    try {
                        let data = snap.docs.map(d => ({ id: d.id, ...d.data() }));
                        if (sort) data.sort(sort);
                        setter(data);
                        markLoaded();
                    } catch (error) {
                        console.error(`Error processing ${key} snapshot:`, error);
                        markLoaded();
                    }
                }, 
                (error) => {
                    console.error(`Error listening to ${key}:`, error);
                    markLoaded();
                }
            );
        });

        return () => unsubs.forEach(unsub => unsub());
    }, [isAuthReady, db, userId, appId]);

    // Ensure recipientAgentId is always valid
    useEffect(() => {
        if (agents.length > 0 && (!recipientAgentId || !agents.some(a => a.id === recipientAgentId))) {
            setRecipientAgentId(agents[0].id);
        } else if (agents.length === 0) {
            setRecipientAgentId('');
        }
    }, [agents, recipientAgentId]);

    // --- API Call Functions ---
    const callTextApi = useCallback(async (prompt, systemPrompt = "You are a helpful assistant.", generationConfig = null) => {
        const apiKey = ""; // API key is injected by the environment
        const model = DEFAULT_MODEL;
        const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;

        const payload = { 
            contents: [{ 
                role: "user", 
                parts: [{ text: `${systemPrompt}\n\n${prompt}` }] 
            }], 
            ...(generationConfig && { generationConfig }) 
        };

        try {
            const response = await fetch(apiUrl, { 
                method: 'POST', 
                headers: { 'Content-Type': 'application/json' }, 
                body: JSON.stringify(payload) 
            });

            if (!response.ok) {
                const errorBody = await response.text();
                console.error("API Error Body:", errorBody);
                throw new Error(`API request failed: ${response.status}`);
            }

            const result = await response.json();

            if (result.candidates?.[0]?.content?.parts?.[0]?.text) {
                return result.candidates[0].content.parts[0].text;
            }

            return "(No response text found)";
        } catch (error) {
            console.error("API call error:", error);
            throw error;
        }
    }, []);

    const callImageApi = useCallback(async (prompt) => {
        const apiKey = ""; // API key is injected by the environment
        const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/imagen-3.0-generate-002:predict?key=${apiKey}`;

        const payload = { 
            instances: [{ prompt }], 
            parameters: { sampleCount: 1 } 
        };

        try {
            const response = await fetch(apiUrl, { 
                method: 'POST', 
                headers: { 'Content-Type': 'application/json' }, 
                body: JSON.stringify(payload) 
            });

            if (!response.ok) {
                const errorBody = await response.text();
                console.error("Image API Error Body:", errorBody);
                throw new Error(`Image API request failed: ${response.status}`);
            }

            const result = await response.json();

            if (result.predictions?.[0]?.bytesBase64Encoded) {
                return result.predictions[0].bytesBase64Encoded;
            }

            throw new Error("Image generation returned no data");
        } catch (error) {
            console.error("Image API error:", error);
            throw error;
        }
    }, []);

    // --- Core Logic and Handlers ---

    // Add a message to the Firestore database
    const addMessageToDb = useCallback(async (message) => {
        if (!collectionsRef.current.messages) return;

        try {
            return await addDoc(collectionsRef.current.messages, { 
                ...message, 
                timestamp: new Date() 
            });
        } catch (error) {
            console.error("Failed to add message:", error);
        }
    }, []);

    // Helper to find an agent by their ID
    const getAgentById = useCallback((id) => {
        return agents.find(a => a.id === id);
    }, [agents]);

    // Text-to-speech function
    const speak = useCallback((text, voiceName) => {
        return new Promise((resolve) => {
            if (!isTtsEnabled || !text || typeof text !== 'string' || text.trim() === '') {
                resolve();
                return;
            }

            const allVoices = window.speechSynthesis?.getVoices() || [];
            if (allVoices.length === 0) {
                resolve();
                return;
            }

            if (window.speechSynthesis.speaking) {
                window.speechSynthesis.cancel();
            }

            const utterance = new SpeechSynthesisUtterance(text.replace(/\*/g, ''));
            utterance.voice = allVoices.find(v => v.name === voiceName) || 
                             allVoices.find(v => v.lang.startsWith('en') && v.default) || 
                             allVoices[0];
            utterance.onend = resolve;
            utterance.onerror = (e) => { 
                console.warn(`TTS error: ${e.error}`, e); 
                resolve(); 
            };

            setTimeout(() => {
                try {
                    window.speechSynthesis.speak(utterance);
                } catch (error) {
                    console.warn("TTS failed:", error);
                    resolve();
                }
            }, 100);
        });
    }, [isTtsEnabled]);

    // Generate and post a bot's response
    const getBotResponse = useCallback(async (finalPrompt, respondingAgent) => {
        if (!respondingAgent) return;

        setIsTurnInProgress(true);
        setIsGenerating(true);

        try {
            const botText = await callTextApi(finalPrompt, respondingAgent.systemPrompt);
            await addMessageToDb({ 
                text: botText, 
                sender: respondingAgent.name, 
                agentId: respondingAgent.id 
            });

            await speak(botText, respondingAgent.voice);
        } catch (error) {
            console.error("Error getting bot response:", error);
            await addMessageToDb({ 
                text: `Error for ${respondingAgent.name}: ${error.message}`, 
                sender: 'system' 
            });
        } finally {
            setIsGenerating(false);
            setIsTurnInProgress(false);
        }
    }, [addMessageToDb, callTextApi, speak]);

    const handleRegenerateMessage = useCallback(async (messageId) => {
        const messageIndex = messages.findIndex(m => m.id === messageId);
        if (messageIndex === -1) return;

        const originalMessage = messages[messageIndex];
        const respondingAgent = getAgentById(originalMessage.agentId);
        if (!respondingAgent) return;

        const historyUpToMessage = messages.slice(0, messageIndex)
            .map(m => `${m.sender}: ${m.text}`)
            .join('\n');

        const goalPrompt = conversationGoal ? `The current conversation goal is: "${conversationGoal}".` : '';
        const finalPrompt = `${goalPrompt}\n\nPrevious conversation:\n${historyUpToMessage}\n\nYour turn, ${respondingAgent.name}. Please provide a different response.`;

        try {
            const botText = await callTextApi(finalPrompt, respondingAgent.systemPrompt);
            await updateDoc(doc(collectionsRef.current.messages, messageId), { text: botText });
            await speak(botText, respondingAgent.voice);
        } catch (error) {
            console.error("Error regenerating response:", error);
        }
    }, [messages, getAgentById, conversationGoal, callTextApi, speak]);

    // Main auto-response loop for automated conversations
    useEffect(() => {
        if (mode !== 'auto' || isGenerating || isTurnInProgress || messages.length === 0 || isPaused) {
            return;
        }

        const lastMessage = messages[messages.length - 1];
        if (lastMessage.sender === 'You' || lastMessage.sender === 'system' || !lastMessage.agentId) {
            return;
        }

        const nextRule = rules.find(rule => rule.sourceId === lastMessage.agentId);
        if (!nextRule?.targetId) return;

        const nextAgent = getAgentById(nextRule.targetId);
        if (!nextAgent) return;

        const timeoutId = setTimeout(async () => {
            try {
                const history = messages.slice(-10).map(m => `${m.sender}: ${m.text}`).join('\n');
                const goalPrompt = conversationGoal ? `The current conversation goal is: "${conversationGoal}".` : '';
                const finalPrompt = `${goalPrompt}\n\nPrevious conversation:\n${history}\n\nYour turn, ${nextAgent.name}. What is your response? Keep it conversational and concise.`;

                await getBotResponse(finalPrompt, nextAgent);
            } catch (error) {
                console.error("Auto-response error:", error);
            }
        }, responseDelay * 1000);

        return () => clearTimeout(timeoutId);
    }, [mode, messages, rules, isGenerating, isPaused, responseDelay, getBotResponse, getAgentById, conversationGoal, isTurnInProgress]);

    // Handler for sending a manual message
    const handleSendMessage = useCallback(async () => {
        if (!inputValue.trim() || !recipientAgentId) return;

        const respondingAgent = getAgentById(recipientAgentId);
        if (!respondingAgent) return;

        const userMessage = { text: inputValue, sender: senderId === 'You' ? 'You' : getAgentById(senderId)?.name || 'You' };
        setInputValue('');

        try {
            await addMessageToDb(userMessage);

            const history = [...messages, userMessage].slice(-10)
                .map(m => `${m.sender}: ${m.text}`)
                .join('\n');

            const goalPrompt = conversationGoal ? `The current conversation goal is: "${conversationGoal}".` : '';
            const finalPrompt = `${goalPrompt}\n\nPrevious conversation:\n${history}\n\nYour turn, ${respondingAgent.name}. What is your response?`;

            await getBotResponse(finalPrompt, respondingAgent);
        } catch (error) {
            console.error("Error sending message:", error);
        }
    }, [inputValue, recipientAgentId, senderId, addMessageToDb, messages, conversationGoal, getBotResponse, getAgentById]);

    // Agent CRUD operations
    const handleAddAgent = useCallback(async (agentData) => {
        if (!collectionsRef.current.agents) return;

        try {
            await addDoc(collectionsRef.current.agents, { 
                ...agentData, 
