                const resizedBlob = await resizeImage(profilePicturePreview, 128, 128, 'image/png'); // Resize to PNG for potentially better quality for profiles
                const filePath = `profile_pictures/${Date.now()}_${profilePictureFile.name}`;
                profilePictureUrl = await uploadFile(filePath, resizedBlob, profilePictureFile.type);
            } catch (error) {
                console.error("Error uploading profile picture:", error);
                // Optionally show an error to the user
                setIsUploading(false);
                return;
            }
        }

        const agentData = { name, systemPrompt, voice, model: DEFAULT_MODEL, profilePictureUrl };
        if (agentToEdit) {
            onUpdate({ ...agentData, id: agentToEdit.id });
        } else {
            onSave(agentData);
        }
        setIsUploading(false);
        onBack();
    };

    const handlePresetSelect = (preset) => {
        setName(preset.name);
        setSystemPrompt(preset.prompt);
        setIsPresetOpen(false);
    };

    return (
        <div className="flex flex-col h-full">
            <form onSubmit={handleSubmit} className="space-y-4 flex-grow overflow-y-auto pr-2">
                <div>
                    <label className="block text-sm font-medium mb-1">Name</label>
                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded" required />
                </div>
                <div>
                    <label className="block text-sm font-medium mb-1">Profile Picture</label>
                    <div className="flex items-center space-x-3">
                        <img
                            src={profilePicturePreview || `https://placehold.co/64x64/7c3aed/ffffff?text=${name.charAt(0) || 'A'}`}
                            alt="Preview"
                            className="w-16 h-16 rounded-md object-cover bg-gray-600"
                        />
                        <input type="file" accept="image/*" onChange={handleFileChange} ref={fileInputRef} className="hidden" />
                        <button type="button" onClick={() => fileInputRef.current?.click()} className="px-3 py-1 bg-gray-600 rounded text-sm">Upload Image</button>
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-medium mb-1">System Prompt</label>
                    <textarea value={systemPrompt} onChange={(e) => setSystemPrompt(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]" required />
                </div>
                {voices.length > 0 && (
                    <div>
                        <label className="block text-sm font-medium mb-1">Voice</label>
                        <select value={voice} onChange={(e) => setVoice(e.target.value)} className="w-full p-2 bg-gray-700 border border-gray-600 rounded">
                            {voices.map(v => <option key={v.name} value={v.name}>{v.name} ({v.lang})</option>)}
                        </select>
                    </div>
                )}
            </form>

            <div className="flex justify-between items-center pt-4 mt-4 border-t border-gray-700 flex-shrink-0">
                <button type="button" onClick={onBack} className="px-3 py-1 bg-gray-600 rounded text-sm flex items-center"><ArrowLeft size={16} className="mr-1" /> Back</button>
                <div className="space-x-2">
                    <button type="button" onClick={() => setIsPresetOpen(true)} className="px-3 py-1 bg-gray-600 rounded text-sm">Presets</button>
                    {agentToEdit && <button type="button" onClick={() => {
                        setConfirmMessage(`Delete ${agentToEdit.name}? This cannot be undone.`);
                        setConfirmAction(() => () => { onRemove(agentToEdit.id); onBack(); });
                        setIsConfirmModalOpen(true);
                    }} className="px-3 py-1 bg-red-500 rounded text-sm">Delete</button>}
                    <button type="button" onClick={handleSubmit} disabled={isUploading} className="px-4 py-2 bg-blue-500 rounded text-white disabled:bg-gray-500">{isUploading ? "Saving..." : (agentToEdit ? "Update" : "Create")}</button>
                </div>
            </div>

            <Modal isOpen={isPresetOpen} onClose={() => setIsPresetOpen(false)} title="Character Presets" maxWidth="max-w-sm">
                <div className="space-y-2">
                    {PRESET_CHARACTERS.map((preset, i) => (
                        <button key={i} onClick={() => handlePresetSelect(preset)} className="w-full p-3 bg-gray-700 hover:bg-gray-600 rounded text-left">
                            <div className="font-medium">{preset.name}</div>
                            <div className="text-xs text-gray-400 truncate">{preset.prompt}</div>
                        </button>
                    ))}
                </div>
            </Modal>
        </div>
    );
};

