const MediaBin = ({ title, clips, onAddToTimeline, onFileUpload, type, setImagePreviewUrl, onRemoveClip }) => {
    // UI for media clips (video/audio)
    const fileInputRef = useRef(null);
    const [uploadProgress, setUploadProgress] = useState({}); // { [fileName]: progress }

    const handleFileClick = () => {
        fileInputRef.current.click();
    };

    const handleActualFileUpload = async (event) => {
        const files = Array.from(event.target.files);
        if (files.length > 0) {
            await onFileUpload(files, type, (fileName, progress) => {
                setUploadProgress(prev => ({...prev, [fileName]: progress }));
            }, (fileName) => {
                setUploadProgress(prev => {
                    const newState = {...prev};
                    delete newState[fileName];
                    return newState;
                });
            });
        }
        if(fileInputRef.current) fileInputRef.current.value = ""; // Reset file input
    };

    return (
        <div className="bg-gray-800 rounded-lg p-3">
            <div className="flex justify-between items-center mb-3">
                <h3 className="font-semibold">{title}</h3>
                <button 
                    onClick={handleFileClick}
                    className="p-1 bg-gray-700 rounded hover:bg-gray-600"
                    title="Upload media"
                >
                    <Upload size={16} />
                </button>
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleActualFileUpload}
                    accept={type === 'video' ? 'video/*' : type === 'audio' ? 'audio/*' : 'image/*'} // Adjusted for general use
                    multiple
                    className="hidden"
                />
            </div>
            <div className="space-y-2 max-h-64 overflow-y-auto">
                {Object.entries(uploadProgress).map(([fileName, progress]) => (
                    <div key={fileName} className="bg-gray-600 p-2 rounded text-sm">
                        Uploading {fileName}: {progress.toFixed(0)}%
                        <div className="w-full bg-gray-500 rounded-full h-1 mt-1">
                            <div className="bg-blue-500 h-1 rounded-full" style={{width: `${progress}%`}}></div>
                        </div>
                    </div>
                ))}
                {clips.length === 0 && Object.keys(uploadProgress).length === 0 ? (
                    <p className="text-center text-gray-500 py-4 text-sm">No {type} clips</p>
                ) : (
                    clips.map(clip => (
                        <div key={clip.id} className="flex items-center justify-between bg-gray-700 p-2 rounded group">
                           <div className="flex items-center space-x-2 truncate cursor-pointer" onClick={() => (clip.type === 'image' || clip.url.startsWith('data:image')) && setImagePreviewUrl(clip.url)}>
                                {clip.type === 'video' ? <FileVideo size={16} /> : clip.type === 'image' ? <img src={clip.url} className="w-8 h-8 object-cover rounded"/> : <Music size={16} />}
                                <span className="truncate text-sm">{clip.name}</span>
                            </div>
                            <div className="flex items-center space-x-1">
                                <button 
                                    onClick={() => onAddToTimeline(clip, type)}
                                    className="p-1 bg-blue-500 rounded hover:bg-blue-400 opacity-0 group-hover:opacity-100 transition-opacity"
                                    title="Add to timeline"
                                >
                                    <Plus size={16} />
                                </button>
                                {onRemoveClip && ( // Conditionally render remove button
                                    <button
                                        onClick={() => onRemoveClip(clip.id, type)}
                                        className="p-1 bg-red-500 rounded hover:bg-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                                        title={`Remove ${type} clip`}
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                )}
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};


const Timeline = ({ videoTracks, audioTracks, onRemove, currentTime, totalDuration, containerRef }) => {
    // Video editor timeline display
    const calculatePosition = (startTime, duration) => { // duration here is totalDuration
        if (!duration) return '0%'; // totalDuration
        return `${(startTime / duration) * 100}%`;
    };

    const calculateWidth = (clipDuration, totalDurationVal) => {
        if (!totalDurationVal) return '0%';
        return `${(clipDuration / totalDurationVal) * 100}%`;
    };

    return (
        <div className="bg-gray-800 rounded-lg p-3 flex-1 overflow-x-auto" ref={containerRef}>
             <div className="relative min-w-full" style={{ height: '6rem', width: `${Math.max(100, totalDuration * 10)}%` /* Ensure minimum width for visibility */ }}>
                {/* Video Track */}
                <div className="absolute top-0 left-0 right-0 h-10 bg-gray-700 rounded mb-2">
                    {videoTracks.map((clip, index) => {
                        let startTime = 0;
                        for (let i = 0; i < index; i++) {
                            startTime += videoTracks[i].duration || 0;
                        }
                        return (
                            <div
                                key={clip.id}
                                className="absolute h-full bg-blue-500 rounded border border-blue-400 flex items-center justify-center"
                                style={{
                                    left: calculatePosition(startTime, totalDuration),
                                    width: calculateWidth(clip.duration || 0, totalDuration),
                                }}
                            >
                                <span className="text-xs truncate px-1">{clip.name}</span>
                                <button
                                    onClick={() => onRemove(clip.id, 'video')}
                                    className="absolute -right-1 -top-1 bg-red-500 rounded-full p-0.5 hover:bg-red-400 z-20" /* Adjusted size and z-index */
                                >
                                    <X size={10} />
                                </button>
                            </div>
                        );
                    })}
                </div>

                {/* Audio Track */}
                <div className="absolute top-12 left-0 right-0 h-10 bg-gray-700 rounded"> {/* Increased top to avoid overlap */}
                    {audioTracks.map((clip, index) => {
                        let startTime = 0;
                        for (let i = 0; i < index; i++) {
                            startTime += audioTracks[i].duration || 0;
                        }
                        return (
                            <div
                                key={clip.id}
                                className="absolute h-full bg-green-500 rounded border border-green-400 flex items-center justify-center"
                                style={{
                                    left: calculatePosition(startTime, totalDuration),
                                    width: calculateWidth(clip.duration || 0, totalDuration),
                                }}
                            >
                                <span className="text-xs truncate px-1">{clip.name}</span>
                                <button
                                    onClick={() => onRemove(clip.id, 'audio')}
                                    className="absolute -right-1 -top-1 bg-red-500 rounded-full p-0.5 hover:bg-red-400 z-20" /* Adjusted size and z-index */
                                >
                                    <X size={10} />
                                </button>
                            </div>
                        );
                    })}
                </div>

                {/* Playhead */}
                {totalDuration > 0 && (
                    <div
                        className="absolute top-0 w-0.5 h-full bg-red-500 z-10"
                        style={{ left: calculatePosition(currentTime, totalDuration) }}
                    ></div>
                )}
            </div>
        </div>
    );
};

