const AiClipIdeasModal = ({ isOpen, onClose, onClipGenerated, callImageApi, callTextApi }) => {
    // Modal to generate a single AI clip from a prompt
    const [prompt, setPrompt] = useState('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [error, setError] = useState('');

    const handleGenerate = async () => {
        if (!prompt.trim()) {
            setError("Please enter a description");
            return;
        }

        setIsGenerating(true);
        setError('');

        try {
            // AI images are directly added with base64 data, not uploaded as files here.
            // The `onClipGenerated` (which is `addGeneratedClipToBin`) handles saving this.
            const imageData = await callImageApi(prompt); // imageData is base64 string
            await onClipGenerated(prompt, imageData, 'image'); // Pass type 'image'
            onClose();
            setPrompt('');
        } catch (err) {
            setError(err.message);
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Generate AI Clip" icon={<Sparkles />}>
            <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium mb-1">Describe the clip you want to generate</label>
                    <textarea
                        value={prompt}
                        onChange={(e) => setPrompt(e.target.value)}
                        className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]"
                        placeholder="Example: 'A futuristic city skyline at sunset with flying cars'"
                    />
                </div>

                {error && <div className="bg-red-900/50 p-3 rounded text-red-300">{error}</div>}

                <div className="flex justify-end space-x-2">
                    <button
                        onClick={() => { onClose(); setPrompt(''); setError('');}}
                        className="px-3 py-1 bg-gray-600 rounded text-sm"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleGenerate}
                        disabled={isGenerating}
                        className="px-3 py-1 bg-blue-500 rounded text-sm disabled:bg-gray-600"
                    >
                        {isGenerating ? 'Generating...' : 'Generate'}
                    </button>
                </div>
            </div>
        </Modal>
    );
};

const AiStoryboardModal = ({ isOpen, onClose, onClipGenerated, callImageApi, callTextApi }) => {
    // Modal to generate a sequence of clips for a storyboard
    const [concept, setConcept] = useState('');
    const [isGeneratingPrompts, setIsGeneratingPrompts] = useState(false);
    const [isGeneratingImages, setIsGeneratingImages] = useState(false);
    const [error, setError] = useState('');
    const [generatedPrompts, setGeneratedPrompts] = useState([]);
    const [selectedPrompts, setSelectedPrompts] = useState([]);

    const handleGeneratePrompts = async () => {
        if (!concept.trim()) {
            setError("Please enter a concept");
            return;
        }

        setIsGeneratingPrompts(true);
        setError('');
        setGeneratedPrompts([]);
        setSelectedPrompts([]);

        try {
            const response = await callTextApi(
                `Generate 5 visual prompts for a storyboard about: ${concept}. ` +
                `Return as a JSON array of strings. Each prompt should describe a distinct scene.`,
                "You are a creative director.",
                { responseMimeType: "application/json" }
            );

            const prompts = JSON.parse(response);
            setGeneratedPrompts(prompts);
        } catch (err) {
            setError(err.message);
        } finally {
            setIsGeneratingPrompts(false);
        }
    };

    const togglePromptSelection = (index) => {
        setSelectedPrompts(prev => 
            prev.includes(index) 
                ? prev.filter(i => i !== index) 
                : [...prev, index]
        );
    };

    const handleGenerateSelected = async () => {
        if (selectedPrompts.length === 0) {
            setError("Please select at least one prompt");
            return;
        }

        setIsGeneratingImages(true);
        setError('');

        try {
            for (const index of selectedPrompts) {
                const prompt = generatedPrompts[index];
                const imageData = await callImageApi(prompt); // base64
                await onClipGenerated(prompt, imageData, 'image'); // Pass type 'image'
            }
            onClose();
            setConcept('');
            setGeneratedPrompts([]);
            setSelectedPrompts([]);
        } catch (err) {
            setError(err.message);
        } finally {
            setIsGeneratingImages(false);
        }
    };

    const handleCloseModal = () => {
        onClose();
        setConcept('');
        setGeneratedPrompts([]);
        setSelectedPrompts([]);
        setError('');
    }

    return (
        <Modal isOpen={isOpen} onClose={handleCloseModal} title="AI Storyboard" icon={<GalleryHorizontal />} maxWidth="max-w-2xl">
            <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium mb-1">Storyboard Concept</label>
                    <textarea
                        value={concept}
                        onChange={(e) => setConcept(e.target.value)}
                        className="w-full p-2 bg-gray-700 border border-gray-600 rounded min-h-[100px]"
                        placeholder="Example: 'A sci-fi adventure about exploring an alien planet'"
                    />
                </div>

                <button
                    onClick={handleGeneratePrompts}
                    disabled={isGeneratingPrompts || isGeneratingImages}
                    className="px-3 py-1 bg-blue-500 rounded text-sm disabled:bg-gray-600"
                >
                    {isGeneratingPrompts ? 'Generating Prompts...' : (generatedPrompts.length ? 'Regenerate Prompts' : 'Generate Prompts')}
                </button>

                {error && <div className="bg-red-900/50 p-3 rounded text-red-300">{error}</div>}

                {generatedPrompts.length > 0 && (
                    <div className="space-y-2">
                        <h4 className="font-semibold">Select prompts to generate:</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2 max-h-60 overflow-y-auto">
                            {generatedPrompts.map((prompt, index) => (
                                <div
                                    key={index}
                                    onClick={() => togglePromptSelection(index)}
                                    className={`p-3 rounded cursor-pointer ${selectedPrompts.includes(index) ? 'bg-blue-900/50 border border-blue-500' : 'bg-gray-700 hover:bg-gray-600'}`}
                                >
                                    <div className="flex items-start">
                                        <input
                                            type="checkbox"
                                            checked={selectedPrompts.includes(index)}
                                            readOnly
                                            className="mt-1 mr-2 accent-blue-500"
                                        />
                                        <span className="text-sm">{prompt}</span>
                                    </div>
                                </div>
                            ))}
                        </div>

                        <div className="flex justify-end space-x-2 pt-2">
                            <button
                                onClick={handleCloseModal}
                                className="px-3 py-1 bg-gray-600 rounded text-sm"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleGenerateSelected}
                                disabled={isGeneratingImages || isGeneratingPrompts || selectedPrompts.length === 0}
                                className="px-3 py-1 bg-green-500 rounded text-sm disabled:bg-gray-600"
                            >
                                {isGeneratingImages ? 'Generating Images...' : `Generate ${selectedPrompts.length} Selected`}
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </Modal>
    );
};

