const MessageBubble = ({ msg }) => {
    // Displays a single chat message
    const { getAgentById, setImagePreviewUrl, handleRegenerateMessage } = useContext(AppContext);
    const agent = msg.agentId ? getAgentById(msg.agentId) : null;
    const isYou = msg.sender === 'You';
    const isSystem = msg.sender === 'system';

    const bubbleClass = cn(
        'p-3 rounded-xl max-w-xl',
        isYou && 'bg-blue-600 text-white self-end',
        isSystem && 'bg-gray-600 text-white text-center italic mx-auto text-sm', // Made system messages smaller
        !isYou && !isSystem && 'bg-gray-700 self-start'
    );

    // Regex to find markdown image syntax or raw URLs
    const imageRegex = /!\[.*?\]\((https?:\/\/\S+\.(?:jpg|jpeg|png|gif|webp))\)|(https?:\/\/\S+\.(?:jpg|jpeg|png|gif|webp))/gi;
    let match;
    const imageUrls = [];
    let textContent = msg.text;

    while((match = imageRegex.exec(msg.text)) !== null) {
        imageUrls.push(match[1] || match[2]);
        // Remove the matched part from textContent for cleaner display if it's markdown
        textContent = textContent.replace(match[0], '').trim();
    }
    // If no markdown images, check if the entire message text itself is a URL (from older system)
    if (imageUrls.length === 0 && /^https?:\/\/\S+\.(?:jpg|jpeg|png|gif|webp)$/.test(msg.text)) {
        // This case might be redundant if the regex above is comprehensive
        // imageUrls.push(msg.text);
        // textContent = ''; // If the whole message is an image URL
    }
    const remainingText = textContent;

    if (isSystem) {
        return (
            <div className={bubbleClass}>
                <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
        );
    }

    return (
        <div className={cn('group flex items-start gap-3 w-full', isYou && 'justify-end')}>
            {!isYou && (
                <img 
                    src={agent?.profilePictureUrl || `https://placehold.co/40x40/7c3aed/ffffff?text=${msg.sender.charAt(0)}`}
                    onError={(e) => {
                        e.target.onerror = null;
                        e.target.src = `https://placehold.co/40x40/7c3aed/ffffff?text=${msg.sender.charAt(0)}`;
                    }}
                    alt={msg.sender}
                    className="w-10 h-10 rounded-full object-cover flex-shrink-0 cursor-pointer bg-gray-600"
                    onClick={() => agent?.profilePictureUrl && setImagePreviewUrl(agent.profilePictureUrl)}
                />
            )}

            <div className={bubbleClass}>
                {!isYou && <div className="font-semibold text-sm mb-1">{msg.sender}</div>}

                {remainingText.trim() && (
                    <p className="whitespace-pre-wrap break-words">{remainingText}</p>
                )}

                {imageUrls.length > 0 && (
                    <div className={cn("mt-2 space-y-2", remainingText.trim() ? "mt-2" : "mt-0")}>
                        {imageUrls.map((url, i) => (
                            <img
                                key={i}
                                src={url}
                                alt={`Attachment ${i}`}
                                className="max-w-xs max-h-60 rounded-md cursor-pointer object-contain" // Adjusted size
                                onClick={() => setImagePreviewUrl(url)}
                            />
                        ))}
                    </div>
                )}
            </div>
             {!isYou && !isSystem && msg.id && ( // Ensure msg.id exists and not system message
                <button onClick={() => handleRegenerateMessage(msg.id)} title="Regenerate message" className="opacity-0 group-hover:opacity-100 transition-opacity p-1 text-gray-400 hover:text-white">
                    <RefreshCw size={14} />
                </button>
            )}
        </div>
    );
};

