const VideoEditorInterface = ({ ...props }) => {
    // Main UI for the video editor view
    const {
        videoClips,
        audioClips,
        timelineVideo,
        timelineAudio,
        isPlaying,
        currentTime,
        previewSource,
        setPreviewSource,
        isDescriptionModalOpen,
        isGeneratingDescription,
        generatedDescription,
        descriptionError,
        isTitleModalOpen,
        isGeneratingTitle,
        generatedTitles,
        titleError,
        isAiClipModalOpen,
        isAiStoryboardModalOpen,
        setIsPlaying,
        setCurrentTime,
        setIsDescriptionModalOpen,
        setIsGeneratingDescription,
        setGeneratedDescription,
        setDescriptionError,
        setIsTitleModalOpen,
        setIsGeneratingTitle,
        setGeneratedTitles,
        setTitleError,
        setIsAiClipModalOpen,
        setIsAiStoryboardModalOpen,
        handleUserFileUpload, // Renamed from handleFileUpload to distinguish
        handleMetadata, // This might need review if URLs are now Firebase
        addToTimeline,
        removeFromTimeline,
        addGeneratedClipToBin, // This is for AI images
        removeClipFromBin, // New function to remove from MediaBin
        callTextApi,
        callImageApi,
        setImagePreviewUrl
    } = useContext(AppContext);

    const previewVideoRef = useRef(null);
    const previewAudioRef = useRef(null); // Added for audio playback
    const timelineContainerRef = useRef(null);

    const totalDuration = useMemo(() => {
        const videoDuration = timelineVideo.reduce((acc, clip) => acc + (clip.duration || 0), 0);
        const audioDuration = timelineAudio.reduce((acc, clip) => acc + (clip.duration || 0), 0);
        return Math.max(videoDuration, audioDuration); // Consider both tracks for total duration
    }, [timelineVideo, timelineAudio]);

    // Playback control logic
    useEffect(() => {
        let intervalId;
        if (isPlaying && totalDuration > 0) {
            intervalId = setInterval(() => {
                setCurrentTime(prev => {
                    if (prev + 0.1 >= totalDuration) {
                        setIsPlaying(false);
                        return 0; // Reset to start
                    }
                    return prev + 0.1;
                });
            }, 100);
        } else if (!isPlaying && currentTime >= totalDuration && totalDuration > 0) {
            // If paused at the end, reset currentTime to 0 to allow replay from start
             setCurrentTime(0);
        }
        return () => clearInterval(intervalId);
    }, [isPlaying, totalDuration, setCurrentTime, setIsPlaying, currentTime]);

    // Update video and audio preview based on playhead position
    useEffect(() => {
        const videoElement = previewVideoRef.current;
        const audioElement = previewAudioRef.current;

        if (!videoElement || !audioElement) return;

        // Video handling
        let activeVideoClip = null;
        let accumulatedVideoTime = 0;
        for (const clip of timelineVideo) {
            const duration = clip.duration || 0;
            if (currentTime >= accumulatedVideoTime && currentTime < accumulatedVideoTime + duration) {
                activeVideoClip = { ...clip, startTimeOnTimeline: accumulatedVideoTime };
                break;
            }
            accumulatedVideoTime += duration;
        }
        setPreviewSource(activeVideoClip); // This is for image display if video is an image

        if (activeVideoClip) {
            if (activeVideoClip.type === 'video' || (activeVideoClip.url && activeVideoClip.url.includes('.mp4'))) { // Check if it's a video file
                if (videoElement.src !== activeVideoClip.url) {
                    videoElement.src = activeVideoClip.url;
                }
                const clipTime = currentTime - activeVideoClip.startTimeOnTimeline;
                if (Math.abs(videoElement.currentTime - clipTime) > 0.2) {
                    videoElement.currentTime = clipTime;
                }
                 videoElement.style.opacity = '1';
            } else { // It's an image or other non-video type
                 videoElement.pause();
                 videoElement.style.opacity = '0'; // Hide video element if current clip is image
            }
        } else {
            videoElement.pause();
            videoElement.src = ''; // Clear src if no active video clip
            videoElement.style.opacity = '0';
            setPreviewSource(null);
        }

        // Audio handling
        let activeAudioClip = null;
        let accumulatedAudioTime = 0;
        for (const clip of timelineAudio) {
            const duration = clip.duration || 0;
            if (currentTime >= accumulatedAudioTime && currentTime < accumulatedAudioTime + duration) {
                activeAudioClip = { ...clip, startTimeOnTimeline: accumulatedAudioTime };
                break;
            }
            accumulatedAudioTime += duration;
        }

        if (activeAudioClip) {
            if (audioElement.src !== activeAudioClip.url) {
                audioElement.src = activeAudioClip.url;
            }
            const clipTime = currentTime - activeAudioClip.startTimeOnTimeline;
            if (Math.abs(audioElement.currentTime - clipTime) > 0.2) {
                audioElement.currentTime = clipTime;
            }
        } else {
            audioElement.pause();
            audioElement.src = ''; // Clear src if no active audio clip
        }

        // Global play/pause
        if (isPlaying && totalDuration > 0) {
            if (activeVideoClip && (activeVideoClip.type === 'video' || (activeVideoClip.url && activeVideoClip.url.includes('.mp4')))) videoElement.play().catch(console.warn); else videoElement.pause();
            if (activeAudioClip) audioElement.play().catch(console.warn); else audioElement.pause();
        } else {
            videoElement.pause();
            audioElement.pause();
        }

    }, [currentTime, timelineVideo, timelineAudio, isPlaying, setPreviewSource, totalDuration]);

    const handleGenerateDescription = async () => {
        if (timelineVideo.length === 0 && timelineAudio.length === 0) {
            setDescriptionError("Add clips to generate a description.");
            setIsDescriptionModalOpen(true); // Open modal to show error
            return;
        }

        setIsGeneratingDescription(true);
        setDescriptionError('');

        try {
            const clipNames = [...timelineVideo, ...timelineAudio].map(c => c.name).join(', ');
            const description = await callTextApi(
                `Based on clips titled: ${clipNames || 'various visual and audio segments'}. ` +
                `Generate a short, engaging YouTube description.`
            );
            setGeneratedDescription(description);
        } catch (error) {
            setDescriptionError(error.message);
        } finally {
            setIsGeneratingDescription(false);
        }
    };

    const openDescriptionModal = () => {
        setIsDescriptionModalOpen(true);
        if (!generatedDescription && !descriptionError) { // Only generate if not already generated and no error
            handleGenerateDescription();
        }
    };

    const handleGenerateTitle = async () => {
        if (timelineVideo.length === 0 && timelineAudio.length === 0) {
            setTitleError("Add clips to suggest titles.");
            setIsTitleModalOpen(true); // Open modal to show error
            return;
        }

        setIsGeneratingTitle(true);
        setTitleError('');

        try {
            const clipNames = [...timelineVideo, ...timelineAudio].map(c => c.name).join(', ');
            const titlesJson = await callTextApi(
                `Based on clips titled: ${clipNames || 'various visual and audio segments'}. ` +
                `Generate 5 creative video titles. Return as a JSON array of strings.`,
                "You are a creative director.",
                { responseMimeType: "application/json" }
            );
            setGeneratedTitles(JSON.parse(titlesJson));
        } catch (error) {
            setTitleError(error.message);
        } finally {
            setIsGeneratingTitle(false);
        }
    };

    const openTitleModal = () => {
        setIsTitleModalOpen(true);
        if (generatedTitles.length === 0 && !titleError) { // Only generate if not already generated and no error
            handleGenerateTitle();
        }
    };

    return (
        <div className="flex h-full">
            {/* Left sidebar - Media bins */}
            <aside className="w-1/4 bg-gray-800 p-4 overflow-y-auto flex flex-col space-y-4">
                <MediaBin 
                    title="Video/Image Clips" 
                    onFileUpload={handleUserFileUpload}
                    clips={videoClips}
                    onAddToTimeline={(clip) => addToTimeline(clip, 'video')} // 'video' type also for images on video track
                    onRemoveClip={(clipId) => removeClipFromBin(clipId, 'videoClips')}
                    type="video" // 'video' encompasses images for this bin
                    setImagePreviewUrl={setImagePreviewUrl}
                />

                <MediaBin 
                    title="Audio Tracks" 
                    onFileUpload={handleUserFileUpload}
                    clips={audioClips}
                    onAddToTimeline={(clip) => addToTimeline(clip, 'audio')}
                    onRemoveClip={(clipId) => removeClipFromBin(clipId, 'audioClips')}
                    type="audio"
                />
            </aside>

            {/* Main content area */}
            <main className="w-3/4 flex flex-col p-4 overflow-hidden">
                {/* Preview area */}
                <div className="bg-black rounded-lg shadow-2xl mb-4 flex-shrink-0 relative h-[50vh]">
                    <video 
                        ref={previewVideoRef}
                        className="w-full h-full object-contain opacity-0" // Start hidden, opacity controlled by JS
                        onLoadedMetadata={(e) => handleMetadata(e.target.duration, previewSource?.id, previewSource?.type === 'audio' ? 'audio' : 'video')} // This might need careful handling with Firebase URLs
                    />
                    <audio ref={previewAudioRef} style={{display: 'none'}} 
                        onLoadedMetadata={(e) => handleMetadata(e.target.duration, /* need active audio clip id */ null, 'audio')} // Similar metadata handling needed
                    />

                    {previewSource?.type === 'image' && ( // If active clip on video track is an image
                        <img 
                            src={previewSource.url} 
                            alt={previewSource.name} 
                            className="w-full h-full object-contain absolute inset-0"
                        />
                    )}

                    {!previewSource && timelineVideo.length === 0 && ( // Show only if no previewSource AND timeline empty
                        <div className="absolute inset-0 flex items-center justify-center text-gray-500">
                            Preview will appear here. Add clips to timeline.
                        </div>
                    )}
                </div>

                {/* Toolbar */}
                <Toolbar 
                    onPlayPause={() => setIsPlaying(!isPlaying)}
                    isPlaying={isPlaying}
                    currentTime={currentTime}
                    totalDuration={totalDuration}
                    onAiStoryboard={() => setIsAiStoryboardModalOpen(true)}
                    onAiClipIdeas={() => setIsAiClipModalOpen(true)}
                    onSuggestTitle={openTitleModal}
                    onGenerateDescription={openDescriptionModal}
                />

                {/* Timeline */}
                <Timeline 
                    videoTracks={timelineVideo}
                    audioTracks={timelineAudio}
                    onRemove={removeFromTimeline}
                    currentTime={currentTime}
                    totalDuration={totalDuration}
                    containerRef={timelineContainerRef}
                />
            </main>

            {/* Modals */}
            <DescriptionModal 
                isOpen={isDescriptionModalOpen}
                onClose={() => setIsDescriptionModalOpen(false)}
                isLoading={isGeneratingDescription}
                description={generatedDescription}
                error={descriptionError}
                onRegenerate={handleGenerateDescription}
            />

            <TitleModal 
                isOpen={isTitleModalOpen}
                onClose={() => setIsTitleModalOpen(false)}
                isLoading={isGeneratingTitle}
                titles={generatedTitles}
                error={titleError}
                onRegenerate={handleGenerateTitle}
            />

            <AiClipIdeasModal 
                isOpen={isAiClipModalOpen}
                onClose={() => setIsAiClipModalOpen(false)}
                onClipGenerated={addGeneratedClipToBin} // addGeneratedClipToBin for AI images
                callImageApi={callImageApi}
                callTextApi={callTextApi}
            />

            <AiStoryboardModal 
                isOpen={isAiStoryboardModalOpen}
                onClose={() => setIsAiStoryboardModalOpen(false)}
                onClipGenerated={addGeneratedClipToBin} // addGeneratedClipToBin for AI images
                callImageApi={callImageApi}
                callTextApi={callTextApi}
            />
        </div>
    );
};

