        uploadFile, // For image attachments
        addMessageToDb, // For sending image messages
        getAgentById,
        isUploadingChatImage, 
        setIsUploadingChatImage
    } = useContext(AppContext);

    const messagesEndRef = useRef(null);
    const inputRef = useRef(null);
    const chatImageInputRef = useRef(null);
    const displayMessages = isReplaying ? replayMessages : messages;

    // Auto-scroll to bottom when messages change
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [displayMessages]);

    // Focus input when not generating
    useEffect(() => {
        if (!isGenerating && !isUploadingChatImage) {
            inputRef.current?.focus();
        }
    }, [isGenerating, isUploadingChatImage]);

    const handleKeyDown = (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            if (inputValue.trim()) handleSendMessage(); // Send only if there's text
        }
    };

    const handleImageFileChange = async (e) => {
        const file = e.target.files[0];
        if (file) {
            setIsUploadingChatImage(true);
            try {
                // For chat, let's not resize aggressively by default, or use a larger size
                const reader = new FileReader();
                reader.onload = async (event) => {
                    const base64Image = event.target.result;
                    // Option 1: Upload original or moderately resized
                    // const imageBlob = await resizeImage(base64Image, 1024, 1024, file.type.startsWith("image/png") ? 'image/png' : 'image/jpeg', 0.8);
                    // For simplicity, let's upload the file directly if it's an image.
                    // Or, convert base64 to blob if we want to use resizeImage consistently
                    let blobToUpload = file;
                    if (file.size > 2 * 1024 * 1024) { // Resize if > 2MB
                         blobToUpload = await resizeImage(base64Image, 1024, 768, file.type.startsWith("image/png") ? 'image/png' : 'image/jpeg', 0.8);
                    }

                    const filePath = `chat_attachments/${Date.now()}_${file.name}`;
                    const downloadURL = await uploadFile(filePath, blobToUpload, blobToUpload.type);

                    const senderName = senderId === 'You' ? 'You' : (getAgentById(senderId)?.name || 'User');
                    // Send as a new message, or append to current input?
                    // For now, send as a new message for simplicity.
                    // Could also be: setInputValue(prev => `${prev} ![image](${downloadURL})`);
                    await addMessageToDb({
                        text: `![Attached Image](${downloadURL})`, // Use Markdown for image
                        sender: senderName,
                        agentId: senderId === 'You' ? null : senderId, // if agent sends image
                        // No recipientAgentId needed here as it's a direct message from sender
                    });
                     // If we want the AI to respond to this image, trigger response:
                    if (recipientAgentId && agents.find(a=>a.id === recipientAgentId)) {
                         handleSendMessage(null, `User sent an image: ${downloadURL}`); // Trigger AI response
                    }

                };
                reader.readAsDataURL(file);

            } catch (error) {
                console.error("Error uploading chat image:", error);
                // TODO: Show error to user
            } finally {
                setIsUploadingChatImage(false);
                if (chatImageInputRef.current) chatImageInputRef.current.value = ""; // Reset file input
            }
        }
    };

    return (
        <div className="grid grid-rows-[auto_1fr_auto] h-full bg-gray-900 text-gray-100 font-sans">
             {isReplaying && (
                <div className="absolute inset-0 bg-black/50 z-20 flex items-center justify-center">
                    <div className="text-white text-xl font-bold flex items-center">
                        <ReplayIcon className="animate-spin mr-2" /> Replaying...
                    </div>
                </div>
            )}
            {/* Header */}
            <header className="bg-gray-800 shadow-sm p-3 z-10 flex items-center gap-2 flex-wrap">
                <button 
                    onClick={() => setIsAgentModalOpen(true)}
                    className="flex items-center gap-2 px-3 py-2 bg-gray-700 rounded-lg text-sm font-semibold hover:bg-gray-600"
                >
                    <Users size={16} />
                    <span>Agents ({agents.length})</span>
                </button>

                <button 
                    onClick={() => setIsGoalModalOpen(true)}
                    className="px-3 py-2 bg-orange-500 text-white rounded-lg text-sm hover:bg-orange-600"
                >
                    🎯 Set Goal
                </button>

                <button 
                    onClick={() => setIsRuleModalOpen(true)}
                    className="px-3 py-2 bg-yellow-500 text-black rounded-lg text-sm hover:bg-yellow-600"
                >
                    📜 Rules
                </button>

                <button 
                    onClick={handleAutomateAll}
                    disabled={isAutomating || isGenerating}
                    className="px-3 py-2 bg-purple-600 text-white rounded-lg text-sm hover:bg-purple-700 disabled:bg-purple-400"
                >
                    {isAutomating ? 'Automating...' : '🚀 Automate'}
                </button>

                <button 
                    onClick={handleCreativeSynthesis}
                    disabled={isSynthesizing || isGenerating}
                    className="px-3 py-2 bg-cyan-600 text-white rounded-lg text-sm hover:bg-cyan-700 disabled:bg-cyan-400"
                >
                    {isSynthesizing ? synthesisStatus : '🎬 Creative Synthesis'}
                </button>

                <button onClick={() => setIsTopicModalOpen(true)} className="px-3 py-2 bg-indigo-500 text-white rounded-lg text-sm hover:bg-indigo-600"><Zap size={16} className="inline mr-1"/>Inject Topic</button>
                <button onClick={handleReplay} disabled={isReplaying || isGenerating} className="px-3 py-2 bg-teal-500 text-white rounded-lg text-sm hover:bg-teal-600 disabled:bg-teal-400"><ReplayIcon size={16} className="inline mr-1"/>Replay</button>
                <button onClick={() => setIsClearModalOpen(true)} className="px-3 py-2 bg-red-800 text-white rounded-lg text-sm hover:bg-red-700"><Eraser size={16} className="inline mr-1"/>Clear</button>


                <div className="flex-grow"></div>

                <div className="flex items-center gap-2">
                    <span className="text-sm font-medium">Mode:</span>
                    <button 
                        onClick={() => setMode(m => m === 'manual' ? 'auto' : 'manual')}
                        className={`px-3 py-1 rounded-full text-sm ${mode === 'auto' ? 'bg-blue-500 text-white' : 'bg-gray-600'}`}
                    >
                        {mode === 'auto' ? 'Auto' : 'Manual'}
                    </button>

                    {mode === 'auto' && (
                        <button 
                            onClick={() => setIsPaused(!isPaused)}
                            className="p-2 text-gray-400 hover:text-white rounded-full"
                            title={isPaused ? "Resume Auto Conversation" : "Pause Auto Conversation"}
                        >
                            {isPaused ? <Play size={16} /> : <Pause size={16} />}
                        </button>
                    )}
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => setIsTtsEnabled(!isTtsEnabled)}
                        className="p-2 text-gray-400 hover:text-white rounded-full"
                         title={isTtsEnabled ? "Disable Text-to-Speech" : "Enable Text-to-Speech"}
                    >
                        {isTtsEnabled ? <Speaker size={16} /> : <VolumeX size={16} />}
                    </button>

                    <button 
                        onClick={() => setIsGalleryOpen(true)}
                        className="p-2 text-gray-400 hover:text-white rounded-full"
                        title="Open Synthesis Gallery"
                    >
                        <GalleryHorizontal size={16} />
                    </button>
                </div>
            </header>

            {/* Messages area */}
            <main className="p-4 overflow-y-auto flex flex-col space-y-4">
                {displayMessages.length > 0 ? (
                    displayMessages.map(msg => (
                        <MessageBubble 
                            key={msg.id} 
                            msg={msg} 
                        />
                    ))
                ) : (
                    <div className="text-center text-gray-500 py-16">
                        No messages yet. Start by adding an agent, sending a message, or using the Automate feature.
                    </div>
                )}

                {isGenerating && <TypingIndicator />}
                <div ref={messagesEndRef} />
            </main>

            {/* Input area */}
            <footer className="bg-gray-800 shadow-inner p-4">
                <div className="flex items-center gap-2 mb-3">
                    <label className="text-sm">From:</label>
                    <select 
                        value={senderId}
                        onChange={e => setSenderId(e.target.value)}
                        className="p-2 border rounded-lg bg-gray-700 border-gray-600 text-sm flex-grow" // flex-grow
                    >
                        <option value="You">You</option>
                        {agents.map(a => (
                            <option key={a.id} value={a.id}>{a.name}</option>
                        ))}
                    </select>

                    <label className="text-sm ml-2">To:</label>
                    <select 
                        value={recipientAgentId}
                        onChange={e => setRecipientAgentId(e.target.value)}
                        className="p-2 border rounded-lg bg-gray-700 border-gray-600 text-sm flex-grow" // flex-grow
                    >
                        <option value="">All (Broadcast - AI might not respond)</option> {/* Clarified "All" behavior */}
                        {agents.map(a => (
                            <option key={a.id} value={a.id}>{a.name}</option>
                        ))}
                    </select>
                </div>

                <div className="flex items-center space-x-2">
                    <input
                        type="file"
                        accept="image/*"
                        ref={chatImageInputRef}
                        className="hidden"
                        onChange={handleImageFileChange}
                        disabled={isUploadingChatImage || isGenerating}
                    />
                    <button
                        onClick={() => chatImageInputRef.current?.click()}
                        className="p-3 bg-gray-700 text-white rounded-full hover:bg-gray-600 disabled:bg-gray-500"
                        disabled={isUploadingChatImage || isGenerating || agents.length === 0}
                        title="Attach Image"
                    >
                        {isUploadingChatImage ? <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white"></div> : <Paperclip size={20} />}
                    </button>
                    <input
                        type="text"
                        ref={inputRef}
                        value={inputValue}
                        onChange={e => setInputValue(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder={isGenerating ? "Thinking..." : (isUploadingChatImage ? "Uploading image..." : "Type a message or drop an image...")}
                        disabled={isGenerating || agents.length === 0 || isUploadingChatImage}
                        className="w-full p-2 bg-transparent border border-gray-600 rounded-full"
                    />

                    <button 
                        onClick={() => handleSendMessage()}
                        className="p-3 bg-blue-500 text-white rounded-full disabled:bg-gray-400"
                        disabled={!inputValue.trim() || isGenerating || agents.length === 0 || isUploadingChatImage}
                        title="Send Message"
                    >
                        <svg className="h-6 w-6 transform rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor"> {/* Icon changed to up arrow */}
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" />
                        </svg>
                    </button>
                </div>
            </footer>

            {/* Modals */}
            <AgentManagerModal 
                isOpen={isAgentModalOpen}
                onClose={() => setIsAgentModalOpen(false)}
                onSave={handleAddAgent}
                onUpdate={handleUpdateAgent}
                onRemove={handleRemoveAgent}
                voices={voices}
                agents={agents}
                setIsConfirmModalOpen={setIsConfirmModalOpen}
                setConfirmAction={setConfirmAction}
                setConfirmMessage={setConfirmMessage}
                uploadFile={uploadFile} // Pass uploadFile for AgentForm
            />

            <GoalModal 
                isOpen={isGoalModalOpen}
                onClose={() => setIsGoalModalOpen(false)}
                onSet={setConversationGoal}
                initialGoal={conversationGoal}
            />

            <RuleModal 
                isOpen={isRuleModalOpen}
                onClose={() => setIsRuleModalOpen(false)}
                rules={rules}
                agents={agents}
            />

            <SynthesisGalleryModal 
                isOpen={isGalleryOpen}
                onClose={() => setIsGalleryOpen(false)}
            />

            <TopicModal 
                isOpen={isTopicModalOpen}
                onClose={() => setIsTopicModalOpen(false)}
                onInject={handleInjectTopic}
                onSuggest={handleSuggestTopic}
            />

            <ClearModal
                isOpen={isClearModalOpen}
                onClose={() => setIsClearModalOpen(false)}
                onClearMessages={handleClearMessages}
                onClearAll={handleClearAll}
            />

            <ConfirmationModal 
                isOpen={isConfirmModalOpen}
                onClose={() => setIsConfirmModalOpen(false)}
                onConfirm={() => {
                    if (confirmAction) confirmAction();
                    setIsConfirmModalOpen(false);
                }}
                message={confirmMessage}
            />

            <ImagePreviewModal 
                imageUrl={imagePreviewUrl}
                onClose={() => setImagePreviewUrl(null)}
            />
        </div>
    );
};

const AppUI = () => {
    // Top-level UI component that switches between views
    const { currentView, setCurrentView } = useContext(AppContext);

    return (
        <div className="flex h-screen bg-gray-900 text-white">
            {/* Sidebar */}
            <nav className="w-20 bg-gray-800 p-2 flex flex-col items-center gap-4">
                <h2 className="font-bold text-lg text-blue-400 mt-2">Suite</h2>

                <button 
                    onClick={() => setCurrentView('chat')}
