    const speak = useCallback((text, voiceName) => {
        return new Promise((resolve) => {
            if (!isTtsEnabled || !text || typeof text !== 'string' || text.trim() === '') {
                resolve();
                return;
            }

            const allVoices = window.speechSynthesis?.getVoices() || [];
            if (allVoices.length === 0) {
                 console.warn("TTS voices not loaded yet.");
                resolve();
                return;
            }

            if (window.speechSynthesis.speaking) {
                window.speechSynthesis.cancel(); // Cancel current speech before starting new
            }

            const utterance = new SpeechSynthesisUtterance(text.replace(/\*/g, '')); // Remove asterisks for smoother speech
            const selectedVoice = voices.find(v => v.name === voiceName)?.voice || 
                                  voices.find(v => v.lang.startsWith('en') && v.default)?.voice || 
                                  voices[0]?.voice;
            if (selectedVoice) {
                utterance.voice = selectedVoice;
            } else {
                console.warn("Could not find specified voice or any default voice for TTS.");
            }

            utterance.onend = resolve;
            utterance.onerror = (e) => { 
                console.warn(`TTS error: ${e.error}`, e); 
                resolve(); 
            };

            // Small delay to ensure any previous cancel() has processed
            setTimeout(() => {
                try {
                    window.speechSynthesis.speak(utterance);
                } catch (error) {
                    console.warn("TTS speak() call failed:", error);
                    resolve();
                }
            }, 50); 
        });
    }, [isTtsEnabled, voices]); // Added `voices` to dependency array

