        try {
            const history = contextMessages.slice(-10).map(m => {
                 // Check for image URLs in message text
                const imageMatch = m.text.match(/!\[.*?\]\((https?:\/\/\S+\.(?:jpg|jpeg|png|gif|webp))\)/);
                if (imageMatch && imageMatch[1]) {
                    return `${m.sender}: [sent an image: ${imageMatch[1]}] ${m.text.replace(imageMatch[0], '').trim()}`;
                }
                return `${m.sender}: ${m.text}`;
            }).join('\n');

            const goalPrompt = conversationGoal ? `The current conversation goal is: "${conversationGoal}".` : '';
            const finalPrompt = `${goalPrompt}\n\nPrevious conversation:\n${history}\n\n${promptContent}`; // promptContent is the user's latest message or instruction

            const botText = await callTextApi(finalPrompt, respondingAgent.systemPrompt);
            await addMessageToDb({ 
                text: botText, 
                sender: respondingAgent.name, 
                agentId: respondingAgent.id 
            });

            await speak(botText, respondingAgent.voice);
        } catch (error) {
            console.error("Error getting bot response:", error);
            await addMessageToDb({ 
                text: `Sorry, ${respondingAgent.name} encountered an error: ${error.message.substring(0, 100)}...`, 
                sender: 'system' 
            });
