    const handleRegenerateMessage = useCallback(async (messageId) => {
        const messageIndex = messages.findIndex(m => m.id === messageId);
        if (messageIndex === -1 || messageIndex === 0) return; // Cant regen first message or non-existent

        const originalMessage = messages[messageIndex];
        const respondingAgent = getAgentById(originalMessage.agentId);
        if (!respondingAgent) return;

        // The prompt for regeneration should be based on the message *before* the one being regenerated.
        const precedingMessage = messages[messageIndex - 1];
        const contextMessages = messages.slice(0, messageIndex); // History up to the message before the one being regenerated

        const promptForAgent = `${precedingMessage.sender} said: "${precedingMessage.text}". Now it's your turn, ${respondingAgent.name}. Please provide a different response than your last one.`;

        setIsGenerating(true); // Indicate regeneration
        try {
            const history = contextMessages.slice(-10).map(m => `${m.sender}: ${m.text}`).join('\n');
            const goalPrompt = conversationGoal ? `The current conversation goal is: "${conversationGoal}".` : '';
            const finalPrompt = `${goalPrompt}\n\nPrevious conversation:\n${history}\n\nYour turn, ${respondingAgent.name}. The previous message from ${precedingMessage.sender} was "${precedingMessage.text}". Give a new response.`;

            const botText = await callTextApi(finalPrompt, respondingAgent.systemPrompt);
            await updateDoc(doc(collectionsRef.current.messages, messageId), { text: botText, timestamp: serverTimestamp() });
            await speak(botText, respondingAgent.voice);
        } catch (error) {
            console.error("Error regenerating response:", error);
            // Optionally, update the message with an error or revert
        } finally {
            setIsGenerating(false);
        }
