    // Main auto-response loop for automated conversations
    useEffect(() => {
        if (mode !== 'auto' || isGenerating || isTurnInProgress || messages.length === 0 || isPaused || agents.length < 2) {
            return;
        }

        const lastMessage = messages[messages.length - 1];
        // Only proceed if last message was from an agent (not 'You' or 'system')
        if (!lastMessage.agentId || lastMessage.sender === 'You' || lastMessage.sender === 'system') {
            return;
        }

        const currentAgent = getAgentById(lastMessage.agentId);
        if (!currentAgent) return;

        const nextRule = rules.find(rule => rule.sourceId === currentAgent.id);
        if (!nextRule?.targetId) {
            // console.log("Auto mode: No rule found for next turn from", currentAgent.name);
            return;
        }

        const nextAgent = getAgentById(nextRule.targetId);
        if (!nextAgent) {
            // console.log("Auto mode: Next agent not found for rule", nextRule);
            return;
        }

        const timeoutId = setTimeout(async () => {
            if (isPaused || mode !== 'auto') return; // Double check state before firing
            try {
                const promptForNextAgent = `It's your turn, ${nextAgent.name}. Respond to ${lastMessage.sender}.`;
                await getBotResponse(promptForNextAgent, nextAgent); // Pass current messages (default)
            } catch (error) {
                console.error("Auto-response error:", error);
            }
        }, responseDelay * 1000);

        return () => clearTimeout(timeoutId);
