        const collRef = collectionsRef.current[collRefKey];
        if (!collRef || !storage || !userId) return;

        for (const file of files) {
            const filePath = `media_bin/${type}/${Date.now()}_${file.name}`;
            try {
                // Using uploadFile which now handles resumable and returns downloadURL
                // For progress, uploadFile would need to be modified or use its direct events
                // Simplified: use uploadFile, progress handling is internal to MediaBin component if desired
                const downloadURL = await uploadFile(filePath, file, { contentType: file.type });

                // Get duration for audio/video after URL is available
                let duration = 0;
                if (type === 'video' || type === 'audio') {
                    try {
                        const tempMedia = document.createElement(type);
                        duration = await new Promise((resolve, reject) => {
                            tempMedia.onloadedmetadata = () => resolve(tempMedia.duration);
                            tempMedia.onerror = () => reject(0); // Default to 0 on error
                            tempMedia.src = downloadURL;
                        });
                    } catch (e) { console.warn("Could not get duration for uploaded media", e); }
                } else if (type === 'image') {
                    duration = 5; // Default 5s for images
                }

                await addDoc(collRef, { 
                    name: file.name, 
                    url: downloadURL, 
                    type: type, // 'video', 'audio', or could be 'image' if MediaBin handles images
                    storagePath: filePath, // Store path for potential deletion
                    duration: duration, 
                    timestamp: serverTimestamp()
                });
                if(onComplete) onComplete(file.name);
                 playSound('beep');
            } catch (error) {
                console.error(`Error uploading ${type} file ${file.name}:`, error);
