    // Helper to clear an entire Firestore collection and associated Storage files
    const clearCollection = useCallback(async (collectionRef, deleteStoragePaths = false, pathField = 'storagePath') => {
        if (!db || !collectionRef) return;

        try {
            const snapshot = await getDocs(collectionRef);
            if (snapshot.empty) return;

            const batch = writeBatch(db);
            const deletePromises = [];

            snapshot.docs.forEach(docSnap => {
                batch.delete(docSnap.ref);
                if (deleteStoragePaths && storage && userId && appId) {
                    const data = docSnap.data();
                    if (data[pathField]) {
                        const fullStoragePath = `${appId}/${userId}/${data[pathField]}`;
                        const fileRef = storageRef(storage, fullStoragePath);
                        deletePromises.push(deleteStorageObject(fileRef).catch(e => console.warn(`Failed to delete ${fullStoragePath}:`, e)));
                    } else if (data.url && data.url.includes('/o/')) { // Fallback for URLs if pathField is missing
                        try {
                           const fileRef = storageRef(storage, data.url); // Assumes URL is Firebase Storage URL
                           deletePromises.push(deleteStorageObject(fileRef).catch(e => console.warn(`Failed to delete by URL ${data.url}:`, e)));
                        } catch (e) { /* ignore if not a valid storage URL */ }
                    }
                }
            });
            await batch.commit();
            await Promise.all(deletePromises);
        } catch (error) {
            console.error("Error clearing collection:", error);
        }
