            // For this version, let's ensure we have minAgentsForScenario, up to maxAgents total.
            if (currentAgents.length < maxAgents) {
                 agentsToCreateCount = Math.max(agentsToCreateCount, Math.min(maxAgents - currentAgents.length, 3)); // Add up to 3 new agents if below max
            }


            let setup = { agents: [], initialScenario: '' };
            if (agentsToCreateCount > 0) {
                 const existingAgentNames = currentAgents.map(a => a.name).join(', ') || "none";
