                 const schema = { type: "OBJECT", properties: { "initialScenario": { "type": "STRING" }, "agents": { "type": "ARRAY", "items": { "type": "OBJECT", "properties": { "name": { "type": "STRING" }, "systemPrompt": { "type": "STRING" } }, "required": ["name", "systemPrompt"] } } }, "required": ["initialScenario", "agents"] };
                 const setupJsonString = await callTextApi(setupPrompt, "You are a creative scenario designer.", { responseMimeType: "application/json", responseSchema: schema });
                 setup = JSON.parse(setupJsonString);
            } else {
                 // No new agents to create, generate initial scenario based on existing agents and goal.
                 const scenarioPrompt = `Create a brief opening sentence for a scene involving these agents: ${currentAgents.map(a=>a.name).join(', ')} with the goal: "${finalConversationGoal}". Response as JSON: {"initialScenario": "your sentence"}`;
                 const schema = {type: "OBJECT", properties: {"initialScenario": {"type": "STRING"}}, required: ["initialScenario"]};
                 const scenarioJson = await callTextApi(scenarioPrompt, "You are a creative scenario writer.", { responseMimeType: "application/json", responseSchema: schema });
                 setup.initialScenario = JSON.parse(scenarioJson).initialScenario;
            }

            const newAgentPayloads = [];
            for (const agentData of setup.agents || []) { // Handle case where setup.agents might be undefined
                try {
                    const picPrompt = `A simple, clean, cartoon-style headshot portrait of: "${agentData.name}, ${agentData.systemPrompt.substring(0,100)}", in a cohesive, digital painting style. No text or artifacts.`;
                    const base64ImageData = await callImageApi(picPrompt);
                    const resizedImageBlob = await resizeImage(`data:image/png;base64,${base64ImageData}`, 128, 128, 'image/png');
                    const profilePictureUrl = await uploadFile(`profile_pictures/auto_${Date.now()}_${agentData.name.replace(/\s+/g, '_')}.png`, resizedImageBlob, { contentType: 'image/png' });
                    newAgentPayloads.push({ ...agentData, model: DEFAULT_MODEL, profilePictureUrl, voice: voices[Math.floor(Math.random() * voices.length)]?.name || '' });
                } catch (error) {
                    console.error("Error creating agent image:", error);
                    newAgentPayloads.push({ ...agentData, model: DEFAULT_MODEL, voice: voices[Math.floor(Math.random() * voices.length)]?.name || '', profilePictureUrl: null }); // Fallback
                }
            }

            const newAgentRefs = await Promise.all(newAgentPayloads.map(payload => addDoc(collectionsRef.current.agents, {...payload, timestamp: serverTimestamp() })));
            const newAgentsWithIds = newAgentRefs.map((ref, i) => ({ ...newAgentPayloads[i], id: ref.id }));
            const allScenarioAgents = [...currentAgents, ...newAgentsWithIds]; // These are the agents for *this* scenario run

            // AI-powered rule generation
            if (allScenarioAgents.length >= minAgentsForScenario) {
                const ruleGenPrompt = `You are a master storyteller. Given a goal and a cast of agents, create a logical conversation flow. Goal: "${finalConversationGoal}". Agents:\n${allScenarioAgents.map(a => `- ${a.name} (id: ${a.id}): ${a.systemPrompt}`).join('\n')}\nReturn a JSON object with a "rules" key, an array of objects with "sourceId" and "targetId" (using the provided agent IDs). The order defines the conversation sequence. Make it interesting and logical, ensuring each agent gets a chance to speak if possible, avoiding immediate self-loops. Create at least ${allScenarioAgents.length} rules, ideally forming a cycle or a compelling narrative path. Max 10 rules.`;
                const ruleSchema = { type: "OBJECT", properties: { "rules": { "type": "ARRAY", "items": { "type": "OBJECT", "properties": { "sourceId": { "type": "STRING" }, "targetId": { "type": "STRING" } }, "required": ["sourceId", "targetId"] } } }, "required": ["rules"] };
                const ruleJsonString = await callTextApi(ruleGenPrompt, "You are a master storyteller.", { responseMimeType: "application/json", responseSchema: ruleSchema });
                const ruleSetup = JSON.parse(ruleJsonString);

                const batch = writeBatch(db);
                (ruleSetup.rules || []).forEach(rule => {
                    const sourceAgent = allScenarioAgents.find(a => a.id === rule.sourceId);
                    const targetAgent = allScenarioAgents.find(a => a.id === rule.targetId);
                    if (sourceAgent && targetAgent && sourceAgent.id !== targetAgent.id) { // Ensure agents exist and not self-rule
                       const ruleRef = doc(collection(db, collectionsRef.current.rules.path)); // Create new doc ref
                       batch.set(ruleRef, { sourceId: sourceAgent.id, targetId: targetAgent.id, timestamp: serverTimestamp() });
                    }
                });
                await batch.commit();
            }

            await addMessageToDb({ text: `Scenario: "${setup.initialScenario || 'The conversation begins...'}"`, sender: 'system' });

            if (allScenarioAgents.length > 0) {
                const firstAgent = allScenarioAgents[0]; // Or pick randomly, or based on rules
                const initialPrompt = `As ${firstAgent.name}, start the conversation. The scene is: "${setup.initialScenario || finalConversationGoal}". Keep your first message concise.`;
                await getBotResponse(initialPrompt, firstAgent);
                setMode('auto');
                setIsPaused(false);
            }

        } catch (error) {
            console.error("Automation error:", error);
            await addMessageToDb({ text: `Full automation failed: ${error.message.substring(0,150)}...`, sender: 'system' });
        } finally {
            setIsAutomating(false);
