    }, [clearCollection, addMessageToDb, callTextApi, callImageApi, getBotResponse, voices, agents, conversationGoal, setConversationGoal, uploadFile, db]); // Added uploadFile, db

    const handleInjectTopic = useCallback(async (topic) => {
