    }, [addMessageToDb]);

    const handleSuggestTopic = useCallback(async () => {
        const history = messages.slice(-5).map(m => `${m.sender}: ${m.text}`).join('\n'); // Shorter history for topic suggestion
        const prompt = `Based on the current conversation goal "${conversationGoal || 'an ongoing discussion'}" and the recent discussion:\n${history}\n\nSuggest a surprising and relevant event or topic to inject into the narrative. Provide only the event description as a short sentence.`;
        try {
            const suggestion = await callTextApi(prompt, "You are a master storyteller creating a plot twist.");
            return suggestion;
