    // "Creative Synthesis" function to summarize and visualize the chat
    const handleCreativeSynthesis = useCallback(async () => {
        const fullTranscript = messages
            .filter(m => m.sender !== 'system' && m.text) // Ensure text exists
            .map(m => `${m.sender}: ${m.text}`)
            .join('\n');

        if (fullTranscript.length < 50) {
            await addMessageToDb({ 
                text: "Need a longer conversation (at least 50 characters of dialogue) to start creative synthesis.", 
                sender: 'system' 
            });
            return;
        }

        setIsSynthesizing(true);
        setSynthesisStatus("Starting synthesis...");
        let jobDocRef; // Define here to use in catch

        try {
            jobDocRef = await addDoc(collectionsRef.current.synthesisJobs, { 
                status: 'processing', 
                timestamp: serverTimestamp(), 
                imagePrompts: [], 
                summary: '', 
            });

            setSynthesisStatus("Summarizing conversation...");
            const summary = await callTextApi(
                `Summarize this conversation transcript into a single, dense paragraph. Max 150 words. TRANSCRIPT:\n${fullTranscript}`, 
                "You are a concise summarizer."
            );

            await updateDoc(jobDocRef, { summary });
            setSynthesisStatus("Generating visual concepts...");

            const promptGenSchema = { type: "OBJECT", properties: { "prompts": { "type": "ARRAY", "items": { "type": "STRING" } } }, required: ["prompts"] };
            const promptGenPrompt = `You are a film director. Based on the summary: "${summary}", and the transcript: "${fullTranscript}", create 3-5 distinct visual prompts for an image generation AI. Each prompt should describe a key narrative scene or concept. Return a JSON object with a "prompts" key containing an array of these string prompts. Focus on visually interesting and diverse scenes.`;

            const promptResultJson = await callTextApi(promptGenPrompt, "You are a creative visual director.", { responseMimeType: "application/json", responseSchema: promptGenSchema });
            const { prompts } = JSON.parse(promptResultJson);

            await updateDoc(jobDocRef, { imagePrompts: prompts || [], status: 'completed' }); // Ensure prompts is an array

            setSynthesisStatus('Synthesis Complete!');
